fn store_source_pack_hierarchical_link_execution_object_pages_from_stored_leaf_group(
    store: &SourcePackFilesystemArtifactStore,
    link_plan_index: &SourcePackHierarchicalLinkPlanIndex,
    group: &SourcePackHierarchicalLinkGroupPage,
    artifact_ref_index: &SourcePackBuildArtifactRefIndex,
) -> Result<(usize, usize), CompileError> {
    validate_source_pack_hierarchical_link_group_page(
        group,
        link_plan_index.target,
        Some(group.group_index),
    )?;
    if group.kind != SourcePackHierarchicalLinkGroupKind::Leaf {
        return Err(source_pack_library_partition_contract_error(format!(
            "hierarchical link execution group {} is not a leaf group",
            group.group_index
        )));
    }
    let mut writer = SourcePackHierarchicalLinkExecutionObjectPageWriter::new(
        store,
        link_plan_index.target,
        group.group_index,
        group.job_index,
        artifact_ref_index,
    );
    for &codegen_job_index in &group.input_codegen_job_indices {
        writer.push_job(codegen_job_index)?;
    }
    let (input_object_count, input_object_page_count) = writer.finish()?;
    if input_object_count != group.input_codegen_job_indices.len() {
        return Err(source_pack_library_partition_contract_error(format!(
            "hierarchical link execution leaf group {} wrote {} object inputs but expected {}",
            group.group_index,
            input_object_count,
            group.input_codegen_job_indices.len()
        )));
    }
    Ok((input_object_count, input_object_page_count))
}

struct SourcePackHierarchicalLinkExecutionPartialPageWriter<'a> {
    store: &'a SourcePackFilesystemArtifactStore,
    target: SourcePackArtifactTarget,
    group_index: usize,
    job_index: usize,
    link_plan_index: &'a SourcePackHierarchicalLinkPlanIndex,
    artifact_ref_index: &'a SourcePackBuildArtifactRefIndex,
    page_index: usize,
    first_input_position: usize,
    input_count: usize,
    current_input_group_indices: Vec<usize>,
    current_input_group_output_keys: Vec<String>,
}

impl<'a> SourcePackHierarchicalLinkExecutionPartialPageWriter<'a> {
    fn new(
        store: &'a SourcePackFilesystemArtifactStore,
        target: SourcePackArtifactTarget,
        group_index: usize,
        job_index: usize,
        link_plan_index: &'a SourcePackHierarchicalLinkPlanIndex,
        artifact_ref_index: &'a SourcePackBuildArtifactRefIndex,
    ) -> Self {
        Self {
            store,
            target,
            group_index,
            job_index,
            link_plan_index,
            artifact_ref_index,
            page_index: 0,
            first_input_position: 0,
            input_count: 0,
            current_input_group_indices: Vec::with_capacity(
                SOURCE_PACK_HIERARCHICAL_LINK_EXECUTION_PARTIAL_DEFAULT_PAGE_SIZE,
            ),
            current_input_group_output_keys: Vec::with_capacity(
                SOURCE_PACK_HIERARCHICAL_LINK_EXECUTION_PARTIAL_DEFAULT_PAGE_SIZE,
            ),
        }
    }

    fn push_group(&mut self, input_group_index: usize) -> Result<(), CompileError> {
        let output_key = source_pack_hierarchical_link_execution_output_key_for_group(
            self.store,
            self.link_plan_index,
            self.artifact_ref_index,
            input_group_index,
        )?;
        self.current_input_group_indices.push(input_group_index);
        self.current_input_group_output_keys.push(output_key);
        if self.current_input_group_indices.len()
            == SOURCE_PACK_HIERARCHICAL_LINK_EXECUTION_PARTIAL_DEFAULT_PAGE_SIZE
        {
            self.flush()?;
        }
        Ok(())
    }

    fn flush(&mut self) -> Result<(), CompileError> {
        if self.current_input_group_indices.is_empty() {
            return Ok(());
        }
        let input_group_indices = std::mem::take(&mut self.current_input_group_indices);
        let input_group_output_keys = std::mem::take(&mut self.current_input_group_output_keys);
        let page = SourcePackHierarchicalLinkExecutionPartialPage {
            version: SOURCE_PACK_HIERARCHICAL_LINK_EXECUTION_PARTIAL_PAGE_VERSION,
            target: self.target,
            group_index: self.group_index,
            job_index: self.job_index,
            page_index: self.page_index,
            first_input_position: self.first_input_position,
            input_count: input_group_indices.len(),
            input_group_indices,
            input_group_output_keys,
        };
        validate_source_pack_hierarchical_link_execution_partial_page(
            &page,
            self.target,
            self.group_index,
            self.page_index,
        )?;
        self.store
            .store_hierarchical_link_execution_partial_page(&page)?;
        self.input_count = self.input_count.saturating_add(page.input_count);
        self.first_input_position = self.first_input_position.saturating_add(page.input_count);
        self.page_index += 1;
        Ok(())
    }

    fn finish(mut self) -> Result<(usize, usize), CompileError> {
        self.flush()?;
        Ok((self.input_count, self.page_index))
    }
}

fn store_source_pack_hierarchical_link_execution_partial_pages_from_stored_reduce_group(
    store: &SourcePackFilesystemArtifactStore,
    link_plan_index: &SourcePackHierarchicalLinkPlanIndex,
    group: &SourcePackHierarchicalLinkGroupPage,
    artifact_ref_index: &SourcePackBuildArtifactRefIndex,
) -> Result<(usize, usize), CompileError> {
    validate_source_pack_hierarchical_link_group_page(
        group,
        link_plan_index.target,
        Some(group.group_index),
    )?;
    if group.kind != SourcePackHierarchicalLinkGroupKind::Reduce {
        return Err(source_pack_library_partition_contract_error(format!(
            "hierarchical link execution group {} is not a reduce group",
            group.group_index
        )));
    }
    let mut writer = SourcePackHierarchicalLinkExecutionPartialPageWriter::new(
        store,
        link_plan_index.target,
        group.group_index,
        group.job_index,
        link_plan_index,
        artifact_ref_index,
    );
    for &input_group_index in &group.input_link_group_indices {
        writer.push_group(input_group_index)?;
    }
    let (input_group_count, input_group_page_count) = writer.finish()?;
    if input_group_count != group.input_link_group_indices.len() {
        return Err(source_pack_library_partition_contract_error(format!(
            "hierarchical link execution reduce group {} wrote {} partial inputs but expected {}",
            group.group_index,
            input_group_count,
            group.input_link_group_indices.len()
        )));
    }
    Ok((input_group_count, input_group_page_count))
}

fn source_pack_hierarchical_link_execution_output_key_for_group(
    store: &SourcePackFilesystemArtifactStore,
    link_plan_index: &SourcePackHierarchicalLinkPlanIndex,
    artifact_ref_index: &SourcePackBuildArtifactRefIndex,
    group_index: usize,
) -> Result<String, CompileError> {
    if group_index == link_plan_index.final_link_group_index {
        validate_source_pack_build_artifact_ref_index(artifact_ref_index, link_plan_index.target)?;
        return Ok(artifact_ref_index.final_output_key.clone());
    }
    let group =
        store.load_hierarchical_link_group_page_for_target(link_plan_index.target, group_index)?;
    Ok(source_pack_hierarchical_link_partial_output_key(
        link_plan_index.target,
        group.group_index,
        group.job_index,
    ))
}

fn store_source_pack_hierarchical_link_execution_compact_index(
    store: &SourcePackFilesystemArtifactStore,
    index: &SourcePackHierarchicalLinkExecutionIndex,
) -> Result<PathBuf, CompileError> {
    validate_source_pack_hierarchical_link_execution_index(index, index.target)?;
    let path = store.hierarchical_link_execution_index_path_for_target(index.target);
    let bytes = serde_json::to_vec_pretty(index).map_err(|err| {
        CompileError::GpuFrontend(format!(
            "serialize source-pack hierarchical link execution index: {err}"
        ))
    })?;
    write_source_pack_filesystem_file_atomically(
        &path,
        &bytes,
        "source-pack hierarchical link execution index",
    )?;
    Ok(path)
}

#[cfg(test)]
fn source_pack_hierarchical_link_execution_plan_from_schedule_pages(
    link_plan_index: &SourcePackHierarchicalLinkPlanIndex,
    link_group_pages: &[SourcePackHierarchicalLinkGroupPage],
    schedule_index: &SourcePackLibraryScheduleIndex,
    schedule_pages: &[SourcePackLibrarySchedulePage],
) -> Result<
    (
        SourcePackHierarchicalLinkExecutionIndex,
        Vec<SourcePackHierarchicalLinkExecutionPage>,
    ),
    CompileError,
> {
    validate_source_pack_hierarchical_link_plan_index(link_plan_index, link_plan_index.target)?;
    validate_source_pack_library_schedule_index(schedule_index, schedule_index.target)?;
    if schedule_index.target != link_plan_index.target {
        return Err(source_pack_library_partition_contract_error(format!(
            "hierarchical link execution target {:?} does not match schedule target {:?}",
            link_plan_index.target, schedule_index.target
        )));
    }
    if schedule_index.link_job_index != link_plan_index.first_link_job_index {
        return Err(source_pack_library_partition_contract_error(format!(
            "hierarchical link execution first link job {} does not match schedule link job {}",
            link_plan_index.first_link_job_index, schedule_index.link_job_index
        )));
    }
    if link_group_pages.len() != link_plan_index.link_group_count {
        return Err(source_pack_library_partition_contract_error(format!(
            "hierarchical link execution has {} link group pages but plan records {}",
            link_group_pages.len(),
            link_plan_index.link_group_count
        )));
    }

    let output_refs = source_pack_library_schedule_output_refs(schedule_index, schedule_pages)?;
    let mut output_keys_by_group = vec![String::new(); link_plan_index.link_group_count];
    let mut pages = Vec::with_capacity(link_group_pages.len());

    for group in link_group_pages {
        validate_source_pack_hierarchical_link_group_page(
            group,
            link_plan_index.target,
            Some(pages.len()),
        )?;
        let final_output = group.group_index == link_plan_index.final_link_group_index;
        let output_key = if final_output {
            output_refs.final_output_ref.key.clone()
        } else {
            source_pack_hierarchical_link_partial_output_key(
                link_plan_index.target,
                group.group_index,
                group.job_index,
            )
        };

        let (input_interfaces, input_objects, input_group_output_keys) = match group.kind {
            SourcePackHierarchicalLinkGroupKind::Leaf => (
                source_pack_hierarchical_link_execution_output_refs_from_schedule(
                    &output_refs.interface_refs_by_job_index,
                    &group.input_frontend_job_indices,
                    SourcePackArtifactKind::LibraryInterface,
                )?,
                source_pack_hierarchical_link_execution_output_refs_from_schedule(
                    &output_refs.object_refs_by_job_index,
                    &group.input_codegen_job_indices,
                    SourcePackArtifactKind::CodegenObject,
                )?,
                Vec::new(),
            ),
            SourcePackHierarchicalLinkGroupKind::Reduce => {
                let input_group_output_keys = group
                    .input_link_group_indices
                    .iter()
                    .map(|&input_group_index| {
                        output_keys_by_group
                            .get(input_group_index)
                            .filter(|key| !key.is_empty())
                            .cloned()
                            .ok_or_else(|| {
                                source_pack_library_partition_contract_error(format!(
                                    "hierarchical link execution group {} references missing output key for input group {}",
                                    group.group_index, input_group_index
                                ))
                            })
                    })
                    .collect::<Result<Vec<_>, _>>()?;
                (Vec::new(), Vec::new(), input_group_output_keys)
            }
        };

        let page = SourcePackHierarchicalLinkExecutionPage {
            version: SOURCE_PACK_HIERARCHICAL_LINK_EXECUTION_PAGE_VERSION,
            target: link_plan_index.target,
            group_index: group.group_index,
            kind: group.kind,
            job_index: group.job_index,
            input_interface_count: input_interfaces.len(),
            input_interface_page_count: 0,
            input_interface_ranges: Vec::new(),
            input_interfaces,
            input_object_count: input_objects.len(),
            input_object_page_count: 0,
            input_objects,
            input_group_count: group.input_link_group_indices.len(),
            input_group_page_count: 0,
            input_group_indices: group.input_link_group_indices.clone(),
            input_group_output_keys,
            source_byte_count: group.source_byte_count,
            source_file_count: group.source_file_count,
            source_line_count: group.source_line_count,
            output_key,
            final_output,
        };
        validate_source_pack_hierarchical_link_execution_page(
            &page,
            link_plan_index.target,
            Some(group.group_index),
        )?;
        output_keys_by_group[group.group_index] = page.output_key.clone();
        pages.push(page);
    }

    let index = SourcePackHierarchicalLinkExecutionIndex {
        version: SOURCE_PACK_HIERARCHICAL_LINK_EXECUTION_INDEX_VERSION,
        target: link_plan_index.target,
        first_link_job_index: link_plan_index.first_link_job_index,
        final_link_group_index: link_plan_index.final_link_group_index,
        final_link_job_index: link_plan_index.final_link_job_index,
        link_group_count: pages.len(),
        final_output_key: output_refs.final_output_ref.key.clone(),
    };
    validate_source_pack_hierarchical_link_execution_index(&index, link_plan_index.target)?;
    validate_source_pack_hierarchical_link_execution_pages(&index, &pages)?;
    Ok((index, pages))
}

#[cfg(test)]
fn source_pack_library_schedule_output_refs(
    schedule_index: &SourcePackLibraryScheduleIndex,
    schedule_pages: &[SourcePackLibrarySchedulePage],
) -> Result<SourcePackLibraryScheduleOutputRefs, CompileError> {
    validate_source_pack_library_schedule_index(schedule_index, schedule_index.target)?;
    if schedule_pages.len() != schedule_index.partition_count {
        return Err(source_pack_library_partition_contract_error(format!(
            "schedule output refs have {} schedule pages but schedule index partition_count {}",
            schedule_pages.len(),
            schedule_index.partition_count
        )));
    }

    let mut interface_refs_by_job_index = BTreeMap::new();
    let mut object_refs_by_job_index = BTreeMap::new();
    let mut source_metadata_by_artifact_index = BTreeMap::new();
    let mut total_source_file_count = 0usize;
    let mut total_source_byte_count = 0usize;
    let mut total_source_line_count = 0usize;

    for page in schedule_pages {
        validate_source_pack_library_schedule_page(
            page,
            schedule_index.target,
            Some(page.partition_index),
        )?;
        let frontend_jobs = if page.frontend_jobs.is_empty() {
            vec![page.frontend_job.clone()]
        } else {
            page.frontend_jobs.clone()
        };
        for frontend_job in frontend_jobs {
            total_source_file_count = total_source_file_count.max(
                frontend_job
                    .first_source_index
                    .saturating_add(frontend_job.source_file_count),
            );
            total_source_byte_count =
                total_source_byte_count.saturating_add(frontend_job.source_bytes);
            total_source_line_count =
                total_source_line_count.saturating_add(frontend_job.source_lines);
            let frontend_ref = source_pack_scheduled_job_output_ref(
                &frontend_job,
                SourcePackArtifactKind::LibraryInterface,
                schedule_index.target,
            )?;
            source_metadata_by_artifact_index.insert(
                frontend_ref.artifact_index,
                SourcePackArtifactSourceMetadata {
                    source_bytes: frontend_job.source_bytes,
                    source_file_count: frontend_job.source_file_count,
                    source_lines: frontend_job.source_lines,
                },
            );
            if interface_refs_by_job_index
                .insert(frontend_ref.producing_job_index, frontend_ref)
                .is_some()
            {
                return Err(source_pack_library_partition_contract_error(format!(
                    "schedule output refs duplicate frontend job {}",
                    frontend_job.job_index
                )));
            }
        }

        for job in &page.codegen_jobs {
            let object_ref = source_pack_scheduled_job_output_ref(
                job,
                SourcePackArtifactKind::CodegenObject,
                schedule_index.target,
            )?;
            source_metadata_by_artifact_index.insert(
                object_ref.artifact_index,
                SourcePackArtifactSourceMetadata {
                    source_bytes: job.source_bytes,
                    source_file_count: job.source_file_count,
                    source_lines: job.source_lines,
                },
            );
            if object_refs_by_job_index
                .insert(object_ref.producing_job_index, object_ref)
                .is_some()
            {
                return Err(source_pack_library_partition_contract_error(format!(
                    "schedule output refs duplicate codegen job {}",
                    job.job_index
                )));
            }
        }
    }

    let frontend_job_count = source_pack_library_schedule_index_frontend_job_count(schedule_index);
    if interface_refs_by_job_index.len() != frontend_job_count {
        return Err(source_pack_library_partition_contract_error(format!(
            "schedule output refs recorded {} interface outputs but schedule index frontend_job_count {}",
            interface_refs_by_job_index.len(),
            frontend_job_count
        )));
    }
    if object_refs_by_job_index.len() != schedule_index.codegen_job_count {
        return Err(source_pack_library_partition_contract_error(format!(
            "schedule output refs recorded {} object outputs but schedule index codegen_job_count {}",
            object_refs_by_job_index.len(),
            schedule_index.codegen_job_count
        )));
    }

    let final_output_ref = SourcePackArtifactRef {
        artifact_index: schedule_index.link_job_index,
        key: source_pack_artifact_key_for_output(
            schedule_index.target,
            SourcePackArtifactKind::LinkedOutput,
            u32::MAX,
            schedule_index.link_job_index,
            0,
            total_source_file_count,
        ),
        producing_job_index: schedule_index.link_job_index,
        kind: SourcePackArtifactKind::LinkedOutput,
    };
    source_metadata_by_artifact_index.insert(
        final_output_ref.artifact_index,
        SourcePackArtifactSourceMetadata {
            source_bytes: total_source_byte_count,
            source_file_count: total_source_file_count,
            source_lines: total_source_line_count,
        },
    );

    Ok(SourcePackLibraryScheduleOutputRefs {
        interface_refs_by_job_index,
        object_refs_by_job_index,
        final_output_ref,
        source_metadata_by_artifact_index,
    })
}

fn source_pack_scheduled_job_output_ref(
    job: &SourcePackJob,
    kind: SourcePackArtifactKind,
    target: SourcePackArtifactTarget,
) -> Result<SourcePackArtifactRef, CompileError> {
    let expected_kind = match job.phase {
        SourcePackJobPhase::LibraryFrontend => SourcePackArtifactKind::LibraryInterface,
        SourcePackJobPhase::Codegen => SourcePackArtifactKind::CodegenObject,
        SourcePackJobPhase::Link => {
            return Err(source_pack_library_partition_contract_error(format!(
                "link job {} output refs require total source metadata",
                job.job_index
            )));
        }
    };
    if kind != expected_kind {
        return Err(source_pack_library_partition_contract_error(format!(
            "job {} phase {:?} cannot produce {:?}",
            job.job_index, job.phase, kind
        )));
    }
    Ok(SourcePackArtifactRef {
        artifact_index: job.job_index,
        key: source_pack_artifact_key_for_output(
            target,
            kind,
            job.library_id,
            job.job_index,
            job.first_source_index,
            job.source_file_count,
        ),
        producing_job_index: job.job_index,
        kind,
    })
}

#[cfg(test)]
fn store_source_pack_build_artifact_ref_pages_from_stored_schedule_pages(
    store: &SourcePackFilesystemArtifactStore,
    schedule_index: &SourcePackLibraryScheduleIndex,
) -> Result<SourcePackBuildArtifactRefIndex, CompileError> {
    validate_source_pack_library_schedule_index(schedule_index, schedule_index.target)?;
    let mut interface_artifact_count = 0usize;
    let mut object_artifact_count = 0usize;
    let mut total_source_file_count = 0usize;
    let mut total_source_byte_count = 0usize;
    let mut total_source_line_count = 0usize;

    for partition_index in 0..schedule_index.partition_count {
        let page =
            store.load_library_schedule_page_for_target(schedule_index.target, partition_index)?;
        validate_source_pack_library_schedule_page(
            &page,
            schedule_index.target,
            Some(partition_index),
        )?;
        source_pack_for_each_stored_schedule_frontend_job(
            store,
            schedule_index,
            &page,
            |_frontend_job_offset, frontend_job, _dependency_job_count| {
                total_source_file_count = total_source_file_count.max(
                    frontend_job
                        .first_source_index
                        .saturating_add(frontend_job.source_file_count),
                );
                total_source_byte_count =
                    total_source_byte_count.saturating_add(frontend_job.source_bytes);
                total_source_line_count =
                    total_source_line_count.saturating_add(frontend_job.source_lines);

                let frontend_ref = source_pack_scheduled_job_output_ref(
                    &frontend_job,
                    SourcePackArtifactKind::LibraryInterface,
                    schedule_index.target,
                )?;
                let frontend_page = source_pack_build_artifact_ref_page(
                    schedule_index.target,
                    frontend_ref,
                    frontend_job.source_bytes,
                    frontend_job.source_file_count,
                    frontend_job.source_lines,
                )?;
                store.store_build_artifact_ref_page(&frontend_page, schedule_index.job_count)?;
                interface_artifact_count += 1;
                Ok(())
            },
        )?;

        source_pack_for_each_stored_schedule_codegen_job(
            store,
            schedule_index,
            &page,
            |_codegen_job_offset, job| {
                let object_ref = source_pack_scheduled_job_output_ref(
                    &job,
                    SourcePackArtifactKind::CodegenObject,
                    schedule_index.target,
                )?;
                let object_page = source_pack_build_artifact_ref_page(
                    schedule_index.target,
                    object_ref,
                    job.source_bytes,
                    job.source_file_count,
                    job.source_lines,
                )?;
                store.store_build_artifact_ref_page(&object_page, schedule_index.job_count)?;
                object_artifact_count += 1;
                Ok(())
            },
        )?;
    }

    let frontend_job_count = source_pack_library_schedule_index_frontend_job_count(schedule_index);
    if interface_artifact_count != frontend_job_count {
        return Err(source_pack_artifact_shard_contract_error(format!(
            "stored artifact refs recorded {} interface artifacts but schedule index frontend_job_count {}",
            interface_artifact_count, frontend_job_count
        )));
    }
    if object_artifact_count != schedule_index.codegen_job_count {
        return Err(source_pack_artifact_shard_contract_error(format!(
            "stored artifact refs recorded {} object artifacts but schedule index codegen_job_count {}",
            object_artifact_count, schedule_index.codegen_job_count
        )));
    }

    let final_output_ref = SourcePackArtifactRef {
        artifact_index: schedule_index.link_job_index,
        key: source_pack_artifact_key_for_output(
            schedule_index.target,
            SourcePackArtifactKind::LinkedOutput,
            u32::MAX,
            schedule_index.link_job_index,
            0,
            total_source_file_count,
        ),
        producing_job_index: schedule_index.link_job_index,
        kind: SourcePackArtifactKind::LinkedOutput,
    };
    let final_output_page = source_pack_build_artifact_ref_page(
        schedule_index.target,
        final_output_ref.clone(),
        total_source_byte_count,
        total_source_file_count,
        total_source_line_count,
    )?;
    store.store_build_artifact_ref_page(&final_output_page, schedule_index.job_count)?;

    let index = SourcePackBuildArtifactRefIndex {
        version: SOURCE_PACK_BUILD_ARTIFACT_REF_INDEX_VERSION,
        target: schedule_index.target,
        artifact_count: schedule_index.job_count,
        interface_artifact_count,
        object_artifact_count,
        final_output_artifact_index: final_output_ref.artifact_index,
        final_output_key: final_output_ref.key,
        total_source_file_count,
        total_source_byte_count,
        total_source_line_count,
    };
    validate_source_pack_build_artifact_ref_index(&index, schedule_index.target)?;
    store.store_build_artifact_ref_index(&index)?;
    Ok(index)
}

fn validate_source_pack_build_artifact_ref_prepare_progress(
    progress: &SourcePackBuildArtifactRefPrepareProgress,
    schedule_index: &SourcePackLibraryScheduleIndex,
    library_partition_index: &SourcePackLibraryPartitionIndex,
) -> Result<(), CompileError> {
    validate_source_pack_library_schedule_index(schedule_index, schedule_index.target)?;
    validate_source_pack_library_partition_index(library_partition_index, schedule_index.target)?;
    if progress.version != SOURCE_PACK_BUILD_ARTIFACT_REF_PREPARE_PROGRESS_VERSION {
        return Err(CompileError::GpuFrontend(format!(
            "unsupported source-pack artifact-ref prepare progress version {}; expected {}",
            progress.version, SOURCE_PACK_BUILD_ARTIFACT_REF_PREPARE_PROGRESS_VERSION
        )));
    }
    if progress.target != schedule_index.target {
        return Err(source_pack_artifact_shard_contract_error(format!(
            "artifact-ref prepare progress target {:?} does not match schedule target {:?}",
            progress.target, schedule_index.target
        )));
    }
    if progress.partition_count != schedule_index.partition_count
        || progress.partition_count != library_partition_index.partition_count
    {
        return Err(source_pack_artifact_shard_contract_error(format!(
            "artifact-ref prepare progress partition count {} does not match schedule/metadata counts {}/{}",
            progress.partition_count,
            schedule_index.partition_count,
            library_partition_index.partition_count
        )));
    }
    if progress.artifact_count != schedule_index.job_count {
        return Err(source_pack_artifact_shard_contract_error(format!(
            "artifact-ref prepare progress artifact count {} does not match schedule job count {}",
            progress.artifact_count, schedule_index.job_count
        )));
    }
    if progress.next_partition_index > progress.partition_count {
        return Err(source_pack_artifact_shard_contract_error(format!(
            "artifact-ref prepare progress next partition {} exceeds partition count {}",
            progress.next_partition_index, progress.partition_count
        )));
    }
    let frontend_job_count = source_pack_library_schedule_index_frontend_job_count(schedule_index);
    if progress.interface_artifact_count > frontend_job_count {
        return Err(source_pack_artifact_shard_contract_error(format!(
            "artifact-ref prepare progress interface artifact count {} exceeds schedule frontend job count {frontend_job_count}",
            progress.interface_artifact_count
        )));
    }
    if progress.object_artifact_count > schedule_index.codegen_job_count {
        return Err(source_pack_artifact_shard_contract_error(format!(
            "artifact-ref prepare progress object artifact count {} exceeds schedule codegen job count {}",
            progress.object_artifact_count, schedule_index.codegen_job_count
        )));
    }
    let expected_page_count = progress
        .interface_artifact_count
        .checked_add(progress.object_artifact_count)
        .ok_or_else(|| {
            source_pack_artifact_shard_contract_error(
                "artifact-ref prepare progress page count overflows",
            )
        })?;
    if progress.artifact_ref_page_count != expected_page_count {
        return Err(source_pack_artifact_shard_contract_error(format!(
            "artifact-ref prepare progress page count {} does not match interface/object count {}",
            progress.artifact_ref_page_count, expected_page_count
        )));
    }
    if progress.total_source_file_count != library_partition_index.source_file_count
        || progress.total_source_byte_count != library_partition_index.source_byte_count
        || progress.total_source_line_count != library_partition_index.source_line_count
    {
        return Err(source_pack_artifact_shard_contract_error(format!(
            "artifact-ref prepare progress source totals {}/{}/{} do not match metadata totals {}/{}/{}",
            progress.total_source_file_count,
            progress.total_source_byte_count,
            progress.total_source_line_count,
            library_partition_index.source_file_count,
            library_partition_index.source_byte_count,
            library_partition_index.source_line_count
        )));
    }
    Ok(())
}

fn store_source_pack_build_artifact_ref_pages_from_stored_schedule_pages_chunk(
    store: &SourcePackFilesystemArtifactStore,
    schedule_index: &SourcePackLibraryScheduleIndex,
    max_new_libraries: usize,
) -> Result<SourcePackFilesystemArtifactRefPrepareStepResult, CompileError> {
    if max_new_libraries == 0 {
        return Err(CompileError::GpuFrontend(
            "source-pack artifact-ref chunk max_new_libraries must be greater than zero".into(),
        ));
    }
    validate_source_pack_library_schedule_index(schedule_index, schedule_index.target)?;
    let metadata_index = store.load_library_partition_index_for_target(schedule_index.target)?;
    validate_source_pack_library_partition_index(&metadata_index, schedule_index.target)?;
    if metadata_index.partition_count != schedule_index.partition_count {
        return Err(source_pack_artifact_shard_contract_error(format!(
            "artifact-ref chunk schedule has {} partitions but metadata has {}",
            schedule_index.partition_count, metadata_index.partition_count
        )));
    }
    if store
        .build_artifact_ref_index_path_for_target(schedule_index.target)
        .is_file()
    {
        let index = store.load_build_artifact_ref_index_for_target(schedule_index.target)?;
        return Ok(SourcePackFilesystemArtifactRefPrepareStepResult {
            target: schedule_index.target,
            complete: true,
            artifact_count: index.artifact_count,
            artifact_ref_page_count: index.artifact_count,
            new_library_count: 0,
            interface_artifact_count: index.interface_artifact_count,
            object_artifact_count: index.object_artifact_count,
            final_output_artifact_index: index.final_output_artifact_index,
            final_output_key: Some(index.final_output_key),
            artifact_ref_index_path: Some(
                store.build_artifact_ref_index_path_for_target(schedule_index.target),
            ),
            total_source_file_count: index.total_source_file_count,
            total_source_byte_count: index.total_source_byte_count,
            total_source_line_count: index.total_source_line_count,
        });
    }

    let progress_path =
        store.build_artifact_ref_prepare_progress_path_for_target(schedule_index.target);
    let mut progress = if progress_path.is_file() {
        store.load_build_artifact_ref_prepare_progress_for_target(
            schedule_index.target,
            schedule_index,
            &metadata_index,
        )?
    } else {
        SourcePackBuildArtifactRefPrepareProgress {
            version: SOURCE_PACK_BUILD_ARTIFACT_REF_PREPARE_PROGRESS_VERSION,
            target: schedule_index.target,
            partition_count: schedule_index.partition_count,
            artifact_count: schedule_index.job_count,
            next_partition_index: 0,
            artifact_ref_page_count: 0,
            interface_artifact_count: 0,
            object_artifact_count: 0,
            total_source_file_count: metadata_index.source_file_count,
            total_source_byte_count: metadata_index.source_byte_count,
            total_source_line_count: metadata_index.source_line_count,
        }
    };
    validate_source_pack_build_artifact_ref_prepare_progress(
        &progress,
        schedule_index,
        &metadata_index,
    )?;

    let mut new_library_count = 0usize;
    while progress.next_partition_index < schedule_index.partition_count
        && new_library_count < max_new_libraries
    {
        let partition_index = progress.next_partition_index;
        let page =
            store.load_library_schedule_page_for_target(schedule_index.target, partition_index)?;
        validate_source_pack_library_schedule_page(
            &page,
            schedule_index.target,
            Some(partition_index),
        )?;
        let frontend_job_count = source_pack_library_schedule_page_frontend_job_count(&page);
        let partition_artifact_ref_count = frontend_job_count
            .checked_add(page.codegen_job_count)
            .ok_or_else(|| {
            source_pack_artifact_shard_contract_error(format!(
                "artifact-ref page count overflows at partition {partition_index}"
            ))
        })?;
        source_pack_store_artifact_ref_pages_for_schedule_partition(store, schedule_index, &page)?;
        progress.interface_artifact_count = progress
            .interface_artifact_count
            .checked_add(frontend_job_count)
            .ok_or_else(|| {
                source_pack_artifact_shard_contract_error(format!(
                    "artifact-ref interface count overflows at partition {partition_index}"
                ))
            })?;
        progress.object_artifact_count = progress
            .object_artifact_count
            .checked_add(page.codegen_job_count)
            .ok_or_else(|| {
                source_pack_artifact_shard_contract_error(format!(
                    "artifact-ref object count overflows at partition {partition_index}"
                ))
            })?;
        progress.artifact_ref_page_count = progress
            .artifact_ref_page_count
            .checked_add(partition_artifact_ref_count)
            .ok_or_else(|| {
                source_pack_artifact_shard_contract_error(format!(
                    "artifact-ref page count overflows at partition {partition_index}"
                ))
            })?;
        progress.next_partition_index =
            progress
                .next_partition_index
                .checked_add(1)
                .ok_or_else(|| {
                    source_pack_artifact_shard_contract_error(
                        "artifact-ref next partition index overflows",
                    )
                })?;
        new_library_count = new_library_count.checked_add(1).ok_or_else(|| {
            source_pack_artifact_shard_contract_error("artifact-ref new library count overflows")
        })?;
        store.store_build_artifact_ref_prepare_progress(
            &progress,
            schedule_index,
            &metadata_index,
        )?;
    }

    let total_interface_artifact_count =
        source_pack_library_schedule_index_frontend_job_count(schedule_index);
    if progress.next_partition_index < schedule_index.partition_count {
        return Ok(SourcePackFilesystemArtifactRefPrepareStepResult {
            target: schedule_index.target,
            complete: false,
            artifact_count: schedule_index.job_count,
            artifact_ref_page_count: progress.artifact_ref_page_count,
            new_library_count,
            interface_artifact_count: total_interface_artifact_count,
            object_artifact_count: schedule_index.codegen_job_count,
            final_output_artifact_index: schedule_index.link_job_index,
            final_output_key: None,
            artifact_ref_index_path: None,
            total_source_file_count: metadata_index.source_file_count,
            total_source_byte_count: metadata_index.source_byte_count,
            total_source_line_count: metadata_index.source_line_count,
        });
    }

    if progress.interface_artifact_count != total_interface_artifact_count {
        return Err(source_pack_artifact_shard_contract_error(format!(
            "artifact-ref chunk recorded {} interface artifacts but schedule index frontend_job_count {}",
            progress.interface_artifact_count, total_interface_artifact_count
        )));
    }
    if progress.object_artifact_count != schedule_index.codegen_job_count {
        return Err(source_pack_artifact_shard_contract_error(format!(
            "artifact-ref chunk recorded {} object artifacts but schedule index codegen_job_count {}",
            progress.object_artifact_count, schedule_index.codegen_job_count
        )));
    }
    if progress.artifact_ref_page_count != schedule_index.link_job_index {
        return Err(source_pack_artifact_shard_contract_error(format!(
            "artifact-ref chunk stored {} non-link artifact pages but schedule link job starts at {}",
            progress.artifact_ref_page_count, schedule_index.link_job_index
        )));
    }
    let final_output_ref = SourcePackArtifactRef {
        artifact_index: schedule_index.link_job_index,
        key: source_pack_artifact_key_for_output(
            schedule_index.target,
            SourcePackArtifactKind::LinkedOutput,
            u32::MAX,
            schedule_index.link_job_index,
            0,
            metadata_index.source_file_count,
        ),
        producing_job_index: schedule_index.link_job_index,
        kind: SourcePackArtifactKind::LinkedOutput,
    };
    let final_output_page = source_pack_build_artifact_ref_page(
        schedule_index.target,
        final_output_ref.clone(),
        metadata_index.source_byte_count,
        metadata_index.source_file_count,
        metadata_index.source_line_count,
    )?;
    store.store_build_artifact_ref_page(&final_output_page, schedule_index.job_count)?;
    let artifact_ref_page_count =
        progress
            .artifact_ref_page_count
            .checked_add(1)
            .ok_or_else(|| {
                source_pack_artifact_shard_contract_error("artifact-ref page count overflows")
            })?;

    let index = SourcePackBuildArtifactRefIndex {
        version: SOURCE_PACK_BUILD_ARTIFACT_REF_INDEX_VERSION,
        target: schedule_index.target,
        artifact_count: schedule_index.job_count,
        interface_artifact_count: total_interface_artifact_count,
        object_artifact_count: schedule_index.codegen_job_count,
        final_output_artifact_index: final_output_ref.artifact_index,
        final_output_key: final_output_ref.key.clone(),
        total_source_file_count: metadata_index.source_file_count,
        total_source_byte_count: metadata_index.source_byte_count,
        total_source_line_count: metadata_index.source_line_count,
    };
    validate_source_pack_build_artifact_ref_index(&index, schedule_index.target)?;
    let artifact_ref_index_path = store.store_build_artifact_ref_index(&index)?;
    Ok(SourcePackFilesystemArtifactRefPrepareStepResult {
        target: schedule_index.target,
        complete: true,
        artifact_count: index.artifact_count,
        artifact_ref_page_count,
        new_library_count,
        interface_artifact_count: index.interface_artifact_count,
        object_artifact_count: index.object_artifact_count,
        final_output_artifact_index: index.final_output_artifact_index,
        final_output_key: Some(index.final_output_key),
        artifact_ref_index_path: Some(artifact_ref_index_path),
        total_source_file_count: index.total_source_file_count,
        total_source_byte_count: index.total_source_byte_count,
        total_source_line_count: index.total_source_line_count,
    })
}

fn source_pack_store_artifact_ref_pages_for_schedule_partition(
    store: &SourcePackFilesystemArtifactStore,
    schedule_index: &SourcePackLibraryScheduleIndex,
    page: &SourcePackLibrarySchedulePage,
) -> Result<(), CompileError> {
    validate_source_pack_library_schedule_index(schedule_index, schedule_index.target)?;
    validate_source_pack_library_schedule_page(
        page,
        schedule_index.target,
        Some(page.partition_index),
    )?;
    source_pack_for_each_stored_schedule_frontend_job(
        store,
        schedule_index,
        page,
        |_frontend_job_offset, frontend_job, _dependency_job_count| {
            let frontend_ref = source_pack_scheduled_job_output_ref(
                &frontend_job,
                SourcePackArtifactKind::LibraryInterface,
                schedule_index.target,
            )?;
            let frontend_page = source_pack_build_artifact_ref_page(
                schedule_index.target,
                frontend_ref,
                frontend_job.source_bytes,
                frontend_job.source_file_count,
                frontend_job.source_lines,
            )?;
            store.store_build_artifact_ref_page(&frontend_page, schedule_index.job_count)?;
            Ok(())
        },
    )?;

    source_pack_for_each_stored_schedule_codegen_job(
        store,
        schedule_index,
        page,
        |_codegen_job_offset, job| {
            let object_ref = source_pack_scheduled_job_output_ref(
                &job,
                SourcePackArtifactKind::CodegenObject,
                schedule_index.target,
            )?;
            let object_page = source_pack_build_artifact_ref_page(
                schedule_index.target,
                object_ref,
                job.source_bytes,
                job.source_file_count,
                job.source_lines,
            )?;
            store.store_build_artifact_ref_page(&object_page, schedule_index.job_count)?;
            Ok(())
        },
    )
}

fn source_pack_build_artifact_ref_page(
    target: SourcePackArtifactTarget,
    artifact_ref: SourcePackArtifactRef,
    source_bytes: usize,
    source_file_count: usize,
    source_lines: usize,
) -> Result<SourcePackBuildArtifactRefPage, CompileError> {
    let page = SourcePackBuildArtifactRefPage {
        version: SOURCE_PACK_BUILD_ARTIFACT_REF_PAGE_VERSION,
        target,
        artifact_index: artifact_ref.artifact_index,
        artifact_ref,
        source_bytes,
        source_file_count,
        source_lines,
    };
    validate_source_pack_build_artifact_ref_page(
        &page,
        target,
        page.artifact_index.saturating_add(1),
        Some(page.artifact_index),
    )?;
    Ok(page)
}

fn source_pack_load_artifact_ref_page_for_index(
    store: &SourcePackFilesystemArtifactStore,
    target: SourcePackArtifactTarget,
    artifact_ref_index: &SourcePackBuildArtifactRefIndex,
    artifact_index: usize,
) -> Result<SourcePackBuildArtifactRefPage, CompileError> {
    validate_source_pack_build_artifact_ref_index(artifact_ref_index, target)?;
    store.load_build_artifact_ref_page_for_target(
        target,
        artifact_index,
        artifact_ref_index.artifact_count,
    )
}

fn source_pack_artifact_ref_for_index_from_stored_pages(
    store: &SourcePackFilesystemArtifactStore,
    target: SourcePackArtifactTarget,
    artifact_ref_index: &SourcePackBuildArtifactRefIndex,
    artifact_index: usize,
    kind: SourcePackArtifactKind,
) -> Result<SourcePackArtifactRef, CompileError> {
    let page = source_pack_load_artifact_ref_page_for_index(
        store,
        target,
        artifact_ref_index,
        artifact_index,
    )?;
    if page.artifact_ref.kind != kind {
        return Err(source_pack_artifact_shard_contract_error(format!(
            "artifact-ref page {} has kind {:?}; expected {:?}",
            artifact_index, page.artifact_ref.kind, kind
        )));
    }
    Ok(page.artifact_ref)
}

fn source_pack_artifact_refs_for_indices_from_stored_pages(
    store: &SourcePackFilesystemArtifactStore,
    target: SourcePackArtifactTarget,
    artifact_ref_index: &SourcePackBuildArtifactRefIndex,
    artifact_indices: &[usize],
) -> Result<Vec<SourcePackArtifactRef>, CompileError> {
    artifact_indices
        .iter()
        .map(|&artifact_index| {
            Ok(source_pack_load_artifact_ref_page_for_index(
                store,
                target,
                artifact_ref_index,
                artifact_index,
            )?
            .artifact_ref)
        })
        .collect()
}

#[cfg(test)]
fn source_pack_hierarchical_link_execution_output_refs_from_schedule(
    refs_by_job_index: &BTreeMap<usize, SourcePackArtifactRef>,
    job_indices: &[usize],
    kind: SourcePackArtifactKind,
) -> Result<Vec<SourcePackArtifactRef>, CompileError> {
    job_indices
        .iter()
        .map(|&job_index| {
            refs_by_job_index.get(&job_index).cloned().ok_or_else(|| {
                source_pack_library_partition_contract_error(format!(
                    "hierarchical link execution references missing {:?} output for job {}",
                    kind, job_index
                ))
            })
        })
        .collect()
}

#[cfg(test)]
fn source_pack_hierarchical_link_execution_final_output_ref(
    artifact_manifest: &SourcePackBuildArtifactManifest,
) -> Result<SourcePackArtifactRef, CompileError> {
    let link_job = artifact_manifest
        .job_schedule
        .jobs
        .iter()
        .find(|job| job.phase == SourcePackJobPhase::Link)
        .ok_or_else(|| {
            source_pack_library_partition_contract_error(
                "hierarchical link execution artifact manifest has no link job",
            )
        })?;
    let job_manifest =
        source_pack_job_artifact_manifest(&artifact_manifest.job_artifacts, link_job.job_index)?;
    Ok(single_output_artifact_ref(job_manifest, SourcePackArtifactKind::LinkedOutput)?.clone())
}

fn source_pack_hierarchical_link_partial_output_key(
    target: SourcePackArtifactTarget,
    group_index: usize,
    job_index: usize,
) -> String {
    let key = format!("partial-link/group-{group_index:08}/job-{job_index:08}");
    match target.key_prefix() {
        Some(prefix) => format!("{prefix}/{key}"),
        None => key,
    }
}

#[cfg(test)]
fn source_pack_hierarchical_link_execution_output_refs_for_jobs(
    artifact_manifest: &SourcePackBuildArtifactManifest,
    job_indices: &[usize],
    kind: SourcePackArtifactKind,
) -> Result<Vec<SourcePackArtifactRef>, CompileError> {
    job_indices
        .iter()
        .map(|&job_index| {
            let job_manifest =
                source_pack_job_artifact_manifest(&artifact_manifest.job_artifacts, job_index)?;
            Ok(single_output_artifact_ref(job_manifest, kind)?.clone())
        })
        .collect()
}

fn source_pack_hierarchical_link_execution_input_interface_count(
    page: &SourcePackHierarchicalLinkExecutionPage,
) -> usize {
    page.input_interface_count
        .max(page.input_interfaces.len().saturating_add(
            source_pack_job_index_range_dependency_count(&page.input_interface_ranges),
        ))
}

fn source_pack_hierarchical_link_execution_input_object_count(
    page: &SourcePackHierarchicalLinkExecutionPage,
) -> usize {
    page.input_object_count.max(page.input_objects.len())
}

fn source_pack_hierarchical_link_execution_input_group_count(
    page: &SourcePackHierarchicalLinkExecutionPage,
) -> usize {
    page.input_group_count.max(page.input_group_indices.len())
}

#[cfg(test)]
fn source_pack_work_queue(
    schedule_index: &SourcePackLibraryScheduleIndex,
    schedule_pages: &[SourcePackLibrarySchedulePage],
    link_plan_index: &SourcePackHierarchicalLinkPlanIndex,
    link_group_pages: &[SourcePackHierarchicalLinkGroupPage],
) -> Result<(SourcePackWorkQueueIndex, Vec<SourcePackWorkQueuePage>), CompileError> {
    validate_source_pack_library_schedule_index(schedule_index, schedule_index.target)?;
    validate_source_pack_hierarchical_link_plan_index(link_plan_index, schedule_index.target)?;
    if schedule_pages.len() != schedule_index.partition_count {
        return Err(source_pack_library_partition_contract_error(format!(
            "work queue has {} schedule pages but schedule index partition_count {}",
            schedule_pages.len(),
            schedule_index.partition_count
        )));
    }
    if link_group_pages.len() != link_plan_index.link_group_count {
        return Err(source_pack_library_partition_contract_error(format!(
            "work queue has {} link group pages but link plan group count {}",
            link_group_pages.len(),
            link_plan_index.link_group_count
        )));
    }

    let final_item_index = link_plan_index.final_link_job_index;
    let mut pages = vec![None; final_item_index.saturating_add(1)];
    for schedule_page in schedule_pages {
        validate_source_pack_library_schedule_page(
            schedule_page,
            schedule_index.target,
            Some(schedule_page.partition_index),
        )?;
        let frontend_page = SourcePackWorkQueuePage {
            version: SOURCE_PACK_WORK_QUEUE_PAGE_VERSION,
            target: schedule_index.target,
            item_index: schedule_page.frontend_job.job_index,
            kind: SourcePackWorkQueueItemKind::LibraryFrontend,
            job_index: schedule_page.frontend_job.job_index,
            dependency_item_indices: schedule_page.frontend_job.dependency_job_indices.clone(),
            dependency_item_count: 0,
            dependency_page_count: 0,
            dependency_item_ranges: Vec::new(),
            dependent_item_indices: Vec::new(),
            dependent_item_count: 0,
            dependent_page_count: 0,
            dependent_item_ranges: Vec::new(),
            artifact_batch_index: None,
            partition_count: 1,
            partition_indices: vec![schedule_page.partition_index],
            link_group_index: None,
            input_frontend_job_count: 0,
            input_frontend_job_indices: Vec::new(),
            input_codegen_job_count: 0,
            input_codegen_job_indices: Vec::new(),
            input_link_group_count: 0,
            input_link_group_indices: Vec::new(),
            source_byte_count: schedule_page.frontend_job.source_bytes,
            source_file_count: schedule_page.frontend_job.source_file_count,
            source_line_count: schedule_page.frontend_job.source_lines,
        };
        source_pack_insert_work_queue_page(&mut pages, frontend_page)?;

        for job in &schedule_page.codegen_jobs {
            let codegen_page = SourcePackWorkQueuePage {
                version: SOURCE_PACK_WORK_QUEUE_PAGE_VERSION,
                target: schedule_index.target,
                item_index: job.job_index,
                kind: SourcePackWorkQueueItemKind::Codegen,
                job_index: job.job_index,
                dependency_item_indices: job.dependency_job_indices.clone(),
                dependency_item_count: 0,
                dependency_page_count: 0,
                dependency_item_ranges: Vec::new(),
                dependent_item_indices: Vec::new(),
                dependent_item_count: 0,
                dependent_page_count: 0,
                dependent_item_ranges: Vec::new(),
                artifact_batch_index: None,
                partition_count: 1,
                partition_indices: vec![schedule_page.partition_index],
                link_group_index: None,
                input_frontend_job_count: 0,
                input_frontend_job_indices: Vec::new(),
                input_codegen_job_count: 0,
                input_codegen_job_indices: Vec::new(),
                input_link_group_count: 0,
                input_link_group_indices: Vec::new(),
                source_byte_count: job.source_bytes,
                source_file_count: job.source_file_count,
                source_line_count: job.source_lines,
            };
            source_pack_insert_work_queue_page(&mut pages, codegen_page)?;
        }
    }

    for group in link_group_pages {
        validate_source_pack_hierarchical_link_group_page(
            group,
            link_plan_index.target,
            Some(group.group_index),
        )?;
        let (kind, dependency_item_indices) = match group.kind {
            SourcePackHierarchicalLinkGroupKind::Leaf => {
                let mut dependencies = group.input_frontend_job_indices.clone();
                dependencies.extend(group.input_codegen_job_indices.iter().copied());
                dependencies.sort_unstable();
                dependencies.dedup();
                (SourcePackWorkQueueItemKind::LinkLeaf, dependencies)
            }
            SourcePackHierarchicalLinkGroupKind::Reduce => {
                let dependencies = group
                    .input_link_group_indices
                    .iter()
                    .map(|input_group_index| {
                        link_plan_index
                            .first_link_job_index
                            .checked_add(*input_group_index)
                            .ok_or_else(|| {
                                source_pack_library_partition_contract_error(format!(
                                    "work queue link group {} input group {} overflows job index",
                                    group.group_index, input_group_index
                                ))
                            })
                    })
                    .collect::<Result<Vec<_>, _>>()?;
                (SourcePackWorkQueueItemKind::LinkReduce, dependencies)
            }
        };
        let link_page = SourcePackWorkQueuePage {
            version: SOURCE_PACK_WORK_QUEUE_PAGE_VERSION,
            target: link_plan_index.target,
            item_index: group.job_index,
            kind,
            job_index: group.job_index,
            dependency_item_indices,
            dependency_item_count: 0,
            dependency_page_count: 0,
            dependency_item_ranges: Vec::new(),
            dependent_item_indices: Vec::new(),
            dependent_item_count: 0,
            dependent_page_count: 0,
            dependent_item_ranges: Vec::new(),
            artifact_batch_index: None,
            partition_count: source_pack_hierarchical_link_group_input_partition_count(group),
            partition_indices: group.input_partition_indices.clone(),
            link_group_index: Some(group.group_index),
            input_frontend_job_count: group.input_frontend_job_indices.len(),
            input_frontend_job_indices: group.input_frontend_job_indices.clone(),
            input_codegen_job_count: group.input_codegen_job_indices.len(),
            input_codegen_job_indices: group.input_codegen_job_indices.clone(),
            input_link_group_count: group.input_link_group_indices.len(),
            input_link_group_indices: group.input_link_group_indices.clone(),
            source_byte_count: group.source_byte_count,
            source_file_count: group.source_file_count,
            source_line_count: group.source_line_count,
        };
        source_pack_insert_work_queue_page(&mut pages, link_page)?;
    }

    let mut pages = pages
        .into_iter()
        .enumerate()
        .map(|(item_index, page)| {
            page.ok_or_else(|| {
                source_pack_library_partition_contract_error(format!(
                    "work queue missing item page {item_index}"
                ))
            })
        })
        .collect::<Result<Vec<_>, _>>()?;
    let dependents_by_item = source_pack_work_queue_dependents_by_item(&pages)?;
    for (page, dependent_item_indices) in pages.iter_mut().zip(dependents_by_item) {
        page.dependent_item_indices = dependent_item_indices;
        validate_source_pack_work_queue_page(page, page.target, Some(page.item_index))?;
    }
    let index = SourcePackWorkQueueIndex {
        version: SOURCE_PACK_WORK_QUEUE_INDEX_VERSION,
        target: schedule_index.target,
        work_item_count: pages.len(),
        artifact_item_count: source_pack_work_queue_artifact_item_count_from_pages(&pages),
        final_item_index,
        final_job_index: link_plan_index.final_link_job_index,
    };
    validate_source_pack_work_queue_index(&index, schedule_index.target)?;
    Ok((index, pages))
}

#[derive(Clone, Debug, PartialEq, Eq, Serialize, Deserialize)]
struct SourcePackWorkQueuePrepareProgress {
    version: u32,
    target: SourcePackArtifactTarget,
    work_item_count: usize,
    next_item_index: usize,
}

fn validate_source_pack_work_queue_prepare_progress(
    progress: &SourcePackWorkQueuePrepareProgress,
    target: SourcePackArtifactTarget,
    work_item_count: usize,
) -> Result<(), CompileError> {
    if progress.version != SOURCE_PACK_WORK_QUEUE_PREPARE_PROGRESS_VERSION {
        return Err(CompileError::GpuFrontend(format!(
            "unsupported source-pack work queue prepare progress version {}; expected {}",
            progress.version, SOURCE_PACK_WORK_QUEUE_PREPARE_PROGRESS_VERSION
        )));
    }
    if progress.target != target {
        return Err(source_pack_library_partition_contract_error(format!(
            "work queue prepare progress target {:?} does not match requested target {:?}",
            progress.target, target
        )));
    }
    if progress.work_item_count != work_item_count {
        return Err(source_pack_library_partition_contract_error(format!(
            "work queue prepare progress item count {} does not match expected {work_item_count}",
            progress.work_item_count
        )));
    }
    if progress.next_item_index > work_item_count {
        return Err(source_pack_library_partition_contract_error(format!(
            "work queue prepare progress next item {} exceeds item count {work_item_count}",
            progress.next_item_index
        )));
    }
    Ok(())
}

fn store_source_pack_work_queue_pages_from_stored_schedule_pages_chunk(
    store: &SourcePackFilesystemArtifactStore,
    schedule_index: &SourcePackLibraryScheduleIndex,
    link_plan_index: &SourcePackHierarchicalLinkPlanIndex,
    max_new_items: usize,
) -> Result<SourcePackFilesystemWorkQueuePrepareStepResult, CompileError> {
    if max_new_items == 0 {
        return Err(CompileError::GpuFrontend(
            "source-pack work queue chunk max_new_items must be greater than zero".into(),
        ));
    }
    validate_source_pack_library_schedule_index(schedule_index, schedule_index.target)?;
    validate_source_pack_hierarchical_link_plan_index(link_plan_index, schedule_index.target)?;
    if schedule_index.link_job_index != link_plan_index.first_link_job_index {
        return Err(source_pack_library_partition_contract_error(format!(
            "work queue chunk first link job {} does not match schedule link job {}",
            link_plan_index.first_link_job_index, schedule_index.link_job_index
        )));
    }
    let final_item_index = link_plan_index.final_link_job_index;
    let work_item_count = final_item_index.saturating_add(1);
    let artifact_item_count = source_pack_library_schedule_index_frontend_job_count(schedule_index)
        .saturating_add(schedule_index.codegen_job_count);
    if store
        .work_queue_index_path_for_target(schedule_index.target)
        .is_file()
    {
        let index = store.load_work_queue_index_for_target(schedule_index.target)?;
        return Ok(SourcePackFilesystemWorkQueuePrepareStepResult {
            target: schedule_index.target,
            complete: true,
            work_item_count: index.work_item_count,
            artifact_item_count: index.artifact_item_count,
            next_item_index: index.work_item_count,
            new_work_item_count: 0,
            work_queue_index_path: Some(
                store.work_queue_index_path_for_target(schedule_index.target),
            ),
        });
    }

    let progress_path = store.work_queue_prepare_progress_path_for_target(schedule_index.target);
    let mut progress = if progress_path.is_file() {
        source_pack_load_work_queue_prepare_progress(store, schedule_index.target, work_item_count)?
    } else {
        SourcePackWorkQueuePrepareProgress {
            version: SOURCE_PACK_WORK_QUEUE_PREPARE_PROGRESS_VERSION,
            target: schedule_index.target,
            work_item_count,
            next_item_index: 0,
        }
    };
    validate_source_pack_work_queue_prepare_progress(
        &progress,
        schedule_index.target,
        work_item_count,
    )?;

    let job_batch_page_index =
        store.load_build_job_batch_page_index_for_target(schedule_index.target)?;
    if job_batch_page_index.scheduled_job_count != schedule_index.job_count {
        return Err(source_pack_library_partition_contract_error(format!(
            "work queue chunk job-batch page index records {} scheduled jobs but schedule index records {}",
            job_batch_page_index.scheduled_job_count, schedule_index.job_count
        )));
    }
    let mut new_work_item_count = 0usize;
    while progress.next_item_index < work_item_count && new_work_item_count < max_new_items {
        source_pack_store_work_queue_page_for_stored_item_index(
            store,
            schedule_index,
            link_plan_index,
            &job_batch_page_index,
            progress.next_item_index,
            work_item_count,
        )?;
        progress.next_item_index = progress.next_item_index.checked_add(1).ok_or_else(|| {
            source_pack_library_partition_contract_error(
                "work queue chunk next item index overflows",
            )
        })?;
        new_work_item_count = new_work_item_count.checked_add(1).ok_or_else(|| {
            source_pack_library_partition_contract_error(
                "work queue chunk new item count overflows",
            )
        })?;
        source_pack_store_work_queue_prepare_progress(store, &progress)?;
    }

    let mut work_queue_index_path = None;
    if progress.next_item_index == work_item_count {
        let index = SourcePackWorkQueueIndex {
            version: SOURCE_PACK_WORK_QUEUE_INDEX_VERSION,
            target: schedule_index.target,
            work_item_count,
            artifact_item_count,
            final_item_index,
            final_job_index: link_plan_index.final_link_job_index,
        };
        validate_source_pack_work_queue_index(&index, schedule_index.target)?;
        work_queue_index_path = Some(store_source_pack_work_queue_compact_index(store, &index)?);
    }

    Ok(SourcePackFilesystemWorkQueuePrepareStepResult {
        target: schedule_index.target,
        complete: work_queue_index_path.is_some(),
        work_item_count,
        artifact_item_count,
        next_item_index: progress.next_item_index,
        new_work_item_count,
        work_queue_index_path,
    })
}

fn source_pack_store_work_queue_page_for_stored_item_index(
    store: &SourcePackFilesystemArtifactStore,
    schedule_index: &SourcePackLibraryScheduleIndex,
    link_plan_index: &SourcePackHierarchicalLinkPlanIndex,
    job_batch_page_index: &SourcePackBuildJobBatchPageIndex,
    item_index: usize,
    work_item_count: usize,
) -> Result<SourcePackWorkQueuePage, CompileError> {
    validate_source_pack_library_schedule_index(schedule_index, schedule_index.target)?;
    validate_source_pack_hierarchical_link_plan_index(link_plan_index, schedule_index.target)?;
    if item_index < schedule_index.link_job_index {
        let locator = store.load_library_schedule_job_locator_page_for_target(
            schedule_index.target,
            item_index,
            schedule_index.job_count,
        )?;
        let partition_index = locator.partition_index.ok_or_else(|| {
            source_pack_library_partition_contract_error(format!(
                "work queue chunk item {item_index} has no partition"
            ))
        })?;
        let schedule_page =
            store.load_library_schedule_page_for_target(schedule_index.target, partition_index)?;
        validate_source_pack_library_schedule_page(
            &schedule_page,
            schedule_index.target,
            Some(partition_index),
        )?;
        let job = source_pack_stored_schedule_job_metadata(store, schedule_index, item_index)?;
        let kind = match job.phase {
            SourcePackJobPhase::LibraryFrontend => SourcePackWorkQueueItemKind::LibraryFrontend,
            SourcePackJobPhase::Codegen => SourcePackWorkQueueItemKind::Codegen,
            SourcePackJobPhase::Link => {
                return Err(source_pack_library_partition_contract_error(format!(
                    "work queue chunk item {item_index} is link job before link group range"
                )));
            }
        };
        let page = SourcePackWorkQueuePage {
            version: SOURCE_PACK_WORK_QUEUE_PAGE_VERSION,
            target: schedule_index.target,
            item_index: job.job_index,
            kind,
            job_index: job.job_index,
            dependency_item_indices: Vec::new(),
            dependency_item_count: 0,
            dependency_page_count: 0,
            dependency_item_ranges: Vec::new(),
            dependent_item_indices: Vec::new(),
            dependent_item_count: 0,
            dependent_page_count: 0,
            dependent_item_ranges: Vec::new(),
            artifact_batch_index:
                source_pack_singleton_artifact_batch_index_for_job_from_stored_locator(
                    store,
                    schedule_index.target,
                    job_batch_page_index,
                    job.job_index,
                )?,
            partition_count: 1,
            partition_indices: vec![schedule_page.partition_index],
            link_group_index: None,
            input_frontend_job_count: 0,
            input_frontend_job_indices: Vec::new(),
            input_codegen_job_count: 0,
            input_codegen_job_indices: Vec::new(),
            input_link_group_count: 0,
            input_link_group_indices: Vec::new(),
            source_byte_count: job.source_bytes,
            source_file_count: job.source_file_count,
            source_line_count: job.source_lines,
        };
        return store_source_pack_work_queue_page_with_dependency_writer(
            store,
            &page,
            work_item_count,
            |writer| {
                source_pack_write_work_queue_dependencies_from_stored_schedule_job(
                    store,
                    schedule_index,
                    job.job_index,
                    writer,
                )
            },
        );
    }

    let group_index = item_index
        .checked_sub(link_plan_index.first_link_job_index)
        .ok_or_else(|| {
            source_pack_library_partition_contract_error(format!(
                "work queue chunk item {item_index} precedes first link job {}",
                link_plan_index.first_link_job_index
            ))
        })?;
    let group =
        store.load_hierarchical_link_group_page_for_target(link_plan_index.target, group_index)?;
    validate_source_pack_hierarchical_link_group_page(
        &group,
        link_plan_index.target,
        Some(group_index),
    )?;
    if group.job_index != item_index {
        return Err(source_pack_library_partition_contract_error(format!(
            "work queue chunk link group {group_index} has job {} but item is {item_index}",
            group.job_index
        )));
    }
    let kind = match group.kind {
        SourcePackHierarchicalLinkGroupKind::Leaf => SourcePackWorkQueueItemKind::LinkLeaf,
        SourcePackHierarchicalLinkGroupKind::Reduce => SourcePackWorkQueueItemKind::LinkReduce,
    };
    let page = SourcePackWorkQueuePage {
        version: SOURCE_PACK_WORK_QUEUE_PAGE_VERSION,
        target: link_plan_index.target,
        item_index: group.job_index,
        kind,
        job_index: group.job_index,
        dependency_item_indices: Vec::new(),
        dependency_item_count: 0,
        dependency_page_count: 0,
        dependency_item_ranges: Vec::new(),
        dependent_item_indices: Vec::new(),
        dependent_item_count: 0,
        dependent_page_count: 0,
        dependent_item_ranges: Vec::new(),
        artifact_batch_index: None,
        partition_count: source_pack_hierarchical_link_group_input_partition_count(&group),
        partition_indices: if matches!(group.kind, SourcePackHierarchicalLinkGroupKind::Leaf) {
            group.input_partition_indices.clone()
        } else {
            Vec::new()
        },
        link_group_index: Some(group.group_index),
        input_frontend_job_count: source_pack_hierarchical_link_group_input_frontend_job_count(
            &group,
        ),
        input_frontend_job_indices: Vec::new(),
        input_codegen_job_count: group.input_codegen_job_indices.len(),
        input_codegen_job_indices: group.input_codegen_job_indices.clone(),
        input_link_group_count: group.input_link_group_indices.len(),
        input_link_group_indices: group.input_link_group_indices.clone(),
        source_byte_count: group.source_byte_count,
        source_file_count: group.source_file_count,
        source_line_count: group.source_line_count,
    };
    store_source_pack_work_queue_page_with_dependency_writer(
        store,
        &page,
        work_item_count,
        |writer| {
            match group.kind {
                SourcePackHierarchicalLinkGroupKind::Leaf => {
                    let Some(&first_codegen_job_index) = group.input_codegen_job_indices.first()
                    else {
                        return Err(source_pack_library_partition_contract_error(format!(
                            "stored work queue link group {} has no codegen jobs",
                            group.group_index
                        )));
                    };
                    source_pack_write_work_queue_dependencies_from_stored_schedule_job(
                        store,
                        schedule_index,
                        first_codegen_job_index,
                        writer,
                    )?;
                    for &codegen_job_index in &group.input_codegen_job_indices {
                        writer.push(codegen_job_index)?;
                    }
                }
                SourcePackHierarchicalLinkGroupKind::Reduce => {
                    for &input_group_index in &group.input_link_group_indices {
                        let input_item_index = link_plan_index
                        .first_link_job_index
                        .checked_add(input_group_index)
                        .ok_or_else(|| {
                            source_pack_library_partition_contract_error(format!(
                                "stored work queue link group {} input group {} overflows job index",
                                group.group_index, input_group_index
                            ))
                        })?;
                        writer.push(input_item_index)?;
                    }
                }
            }
            Ok(())
        },
    )
}

fn source_pack_store_work_queue_prepare_progress(
    store: &SourcePackFilesystemArtifactStore,
    progress: &SourcePackWorkQueuePrepareProgress,
) -> Result<PathBuf, CompileError> {
    validate_source_pack_work_queue_prepare_progress(
        progress,
        progress.target,
        progress.work_item_count,
    )?;
    let path = store.work_queue_prepare_progress_path_for_target(progress.target);
    let bytes = serde_json::to_vec_pretty(progress).map_err(|err| {
        CompileError::GpuFrontend(format!(
            "serialize source-pack work queue prepare progress: {err}"
        ))
    })?;
    write_source_pack_filesystem_file_atomically(
        &path,
        &bytes,
        "source-pack work queue prepare progress",
    )?;
    Ok(path)
}

fn source_pack_load_work_queue_prepare_progress(
    store: &SourcePackFilesystemArtifactStore,
    target: SourcePackArtifactTarget,
    work_item_count: usize,
) -> Result<SourcePackWorkQueuePrepareProgress, CompileError> {
    let path = store.work_queue_prepare_progress_path_for_target(target);
    let bytes = fs::read(&path).map_err(|err| {
        CompileError::GpuFrontend(format!(
            "read source-pack work queue prepare progress {}: {err}",
            path.display()
        ))
    })?;
    let progress =
        serde_json::from_slice::<SourcePackWorkQueuePrepareProgress>(&bytes).map_err(|err| {
            CompileError::GpuFrontend(format!(
                "parse source-pack work queue prepare progress {}: {err}",
                path.display()
            ))
        })?;
    validate_source_pack_work_queue_prepare_progress(&progress, target, work_item_count)?;
    Ok(progress)
}

fn source_pack_write_work_queue_dependencies_from_stored_schedule_job(
    store: &SourcePackFilesystemArtifactStore,
    schedule_index: &SourcePackLibraryScheduleIndex,
    job_index: usize,
    writer: &mut SourcePackWorkQueueDependencyPageWriter<'_>,
) -> Result<(), CompileError> {
    let job_page = store.load_library_schedule_job_page_for_target(
        schedule_index.target,
        job_index,
        schedule_index.job_count,
    )?;
    source_pack_for_each_schedule_job_explicit_dependency_index(
        store,
        schedule_index,
        &job_page,
        |dependency_job_index| writer.push(dependency_job_index),
    )?;
    for range in &job_page.dependency_job_ranges {
        writer.push_range(range.first_job_index, range.job_count)?;
    }
    Ok(())
}

fn source_pack_singleton_artifact_batch_index_for_job_from_stored_locator(
    store: &SourcePackFilesystemArtifactStore,
    target: SourcePackArtifactTarget,
    index: &SourcePackBuildJobBatchPageIndex,
    job_index: usize,
) -> Result<Option<usize>, CompileError> {
    validate_source_pack_build_job_batch_page_index(index, target)?;
    if job_index >= index.scheduled_job_count {
        return Err(source_pack_artifact_shard_contract_error(format!(
            "work queue job {job_index} exceeds scheduled job count {}",
            index.scheduled_job_count
        )));
    }
    let locator = store.load_build_job_batch_job_locator_page_for_target(
        target,
        job_index,
        index.scheduled_job_count,
    )?;
    if locator.batch_index >= index.batch_count {
        return Err(source_pack_artifact_shard_contract_error(format!(
            "work queue job {job_index} locator points at missing batch {}",
            locator.batch_index
        )));
    }
    let page = store.load_build_job_batch_page_for_target(target, locator.batch_index)?;
    if !page.batch.job_indices.contains(&job_index) {
        return Err(source_pack_artifact_shard_contract_error(format!(
            "work queue job {job_index} locator points at batch {} with jobs {:?}",
            locator.batch_index, page.batch.job_indices
        )));
    }
    Ok(match page.batch.job_indices.as_slice() {
        [single_job_index] if *single_job_index == job_index => Some(locator.batch_index),
        _ => None,
    })
}

fn source_pack_work_queue_append_dependent_page(
    store: &SourcePackFilesystemArtifactStore,
    target: SourcePackArtifactTarget,
    dependency_item_index: usize,
    dependent_item_index: usize,
    work_item_count: usize,
) -> Result<(), CompileError> {
    if dependency_item_index >= work_item_count || dependent_item_index >= work_item_count {
        return Err(source_pack_library_partition_contract_error(format!(
            "work queue dependent edge {dependency_item_index}->{dependent_item_index} exceeds item count {work_item_count}"
        )));
    }
    if dependent_item_index <= dependency_item_index {
        return Err(source_pack_library_partition_contract_error(format!(
            "work queue dependent edge {dependency_item_index}->{dependent_item_index} is not forward"
        )));
    }
    let mut dependency_page =
        store.load_work_queue_page_for_target(target, dependency_item_index)?;
    if !dependency_page.dependent_item_indices.is_empty() {
        return Err(source_pack_library_partition_contract_error(format!(
            "work queue page {dependency_item_index} mixes inline dependents with stored dependent pages"
        )));
    }
    if dependency_page.dependent_item_ranges.iter().any(|range| {
        range
            .iter()
            .is_some_and(|indices| indices.contains(&dependent_item_index))
    }) {
        return Err(source_pack_library_partition_contract_error(format!(
            "work queue page {dependency_item_index} contains duplicate ranged dependent item {dependent_item_index}"
        )));
    }

    let dependent_position = dependency_page.dependent_item_count;
    let page_index = dependent_position / SOURCE_PACK_WORK_QUEUE_DEPENDENTS_DEFAULT_PAGE_SIZE;
    let is_new_dependents_page =
        dependent_position % SOURCE_PACK_WORK_QUEUE_DEPENDENTS_DEFAULT_PAGE_SIZE == 0;
    let mut dependents_page = if is_new_dependents_page {
        SourcePackWorkQueueDependentsPage {
            version: SOURCE_PACK_WORK_QUEUE_DEPENDENTS_PAGE_VERSION,
            target,
            item_index: dependency_item_index,
            page_index,
            first_dependent_position: page_index
                .saturating_mul(SOURCE_PACK_WORK_QUEUE_DEPENDENTS_DEFAULT_PAGE_SIZE),
            dependent_count: 0,
            dependent_item_indices: Vec::new(),
        }
    } else {
        store.load_work_queue_dependents_page_for_target(
            target,
            dependency_item_index,
            page_index,
        )?
    };

    dependents_page
        .dependent_item_indices
        .push(dependent_item_index);
    dependents_page.dependent_count = dependents_page.dependent_item_indices.len();
    validate_source_pack_work_queue_dependents_page(
        &dependents_page,
        target,
        dependency_item_index,
        page_index,
    )?;
    store.store_work_queue_dependents_page(&dependents_page)?;

    dependency_page.dependent_item_count = dependency_page.dependent_item_count.saturating_add(1);
    dependency_page.dependent_page_count = dependency_page
        .dependent_item_count
        .div_ceil(SOURCE_PACK_WORK_QUEUE_DEPENDENTS_DEFAULT_PAGE_SIZE);
    validate_source_pack_work_queue_page(&dependency_page, target, Some(dependency_item_index))?;
    store.store_work_queue_page(&dependency_page)?;
    Ok(())
}

fn source_pack_work_queue_try_append_dependent_range(
    store: &SourcePackFilesystemArtifactStore,
    target: SourcePackArtifactTarget,
    dependency_item_index: usize,
    first_dependent_item_index: usize,
    dependent_item_count: usize,
    work_item_count: usize,
) -> Result<bool, CompileError> {
    if dependent_item_count == 0 {
        return Ok(true);
    }
    let end_dependent_item_index =
        first_dependent_item_index
            .checked_add(dependent_item_count)
            .ok_or_else(|| {
                source_pack_library_partition_contract_error(format!(
                    "work queue dependent range {dependency_item_index}->{first_dependent_item_index}+{dependent_item_count} overflows"
                ))
            })?;
    if dependency_item_index >= work_item_count || end_dependent_item_index > work_item_count {
        return Err(source_pack_library_partition_contract_error(format!(
            "work queue dependent range {dependency_item_index}->{first_dependent_item_index}..{end_dependent_item_index} exceeds item count {work_item_count}"
        )));
    }
    if first_dependent_item_index <= dependency_item_index {
        return Err(source_pack_library_partition_contract_error(format!(
            "work queue dependent range {dependency_item_index}->{first_dependent_item_index}..{end_dependent_item_index} is not forward"
        )));
    }
    let mut dependency_page =
        store.load_work_queue_page_for_target(target, dependency_item_index)?;
    if !dependency_page.dependent_item_indices.is_empty() {
        return Err(source_pack_library_partition_contract_error(format!(
            "work queue page {dependency_item_index} mixes inline dependents with stored dependent ranges"
        )));
    }
    if let Some(range) = dependency_page.dependent_item_ranges.iter().find(|range| {
        range.end_job_index().is_some_and(|range_end| {
            first_dependent_item_index < range_end
                && range.first_job_index < end_dependent_item_index
        })
    }) {
        let duplicate_end = range
            .end_job_index()
            .unwrap_or(range.first_job_index.saturating_add(range.job_count));
        return Err(source_pack_library_partition_contract_error(format!(
            "work queue page {dependency_item_index} dependent range {first_dependent_item_index}..{end_dependent_item_index} overlaps existing range {}..{}",
            range.first_job_index, duplicate_end
        )));
    }
    if !source_pack_try_push_dependent_item_range(
        &mut dependency_page.dependent_item_ranges,
        dependency_item_index,
        first_dependent_item_index,
        dependent_item_count,
    )? {
        return Ok(false);
    }
    validate_source_pack_work_queue_page(&dependency_page, target, Some(dependency_item_index))?;
    store.store_work_queue_page(&dependency_page)?;
    Ok(true)
}

fn source_pack_append_work_queue_dependent_range_to_dependency_range(
    store: &SourcePackFilesystemArtifactStore,
    target: SourcePackArtifactTarget,
    first_dependency_item_index: usize,
    dependency_item_count: usize,
    first_dependent_item_index: usize,
    dependent_item_count: usize,
    work_item_count: usize,
) -> Result<(), CompileError> {
    if dependency_item_count == 0 || dependent_item_count == 0 {
        return Ok(());
    }
    let dependency_end = first_dependency_item_index
        .checked_add(dependency_item_count)
        .ok_or_else(|| {
            source_pack_library_partition_contract_error(format!(
                "work queue reverse dependency range {first_dependency_item_index}+{dependency_item_count} overflows"
            ))
        })?;
    let dependent_end = first_dependent_item_index
        .checked_add(dependent_item_count)
        .ok_or_else(|| {
            source_pack_library_partition_contract_error(format!(
                "work queue reverse dependent range {first_dependent_item_index}+{dependent_item_count} overflows"
            ))
        })?;
    if dependency_end > work_item_count || dependent_end > work_item_count {
        return Err(source_pack_library_partition_contract_error(format!(
            "work queue reverse range dependencies {}..{} dependents {}..{} exceed item count {}",
            first_dependency_item_index,
            dependency_end,
            first_dependent_item_index,
            dependent_end,
            work_item_count
        )));
    }

    for dependency_item_index in first_dependency_item_index..dependency_end {
        if source_pack_work_queue_try_append_dependent_range(
            store,
            target,
            dependency_item_index,
            first_dependent_item_index,
            dependent_item_count,
            work_item_count,
        )? {
            continue;
        }
        for dependent_item_index in first_dependent_item_index..dependent_end {
            source_pack_work_queue_append_dependent_page(
                store,
                target,
                dependency_item_index,
                dependent_item_index,
                work_item_count,
            )?;
        }
    }
    Ok(())
}

struct SourcePackWorkQueueDependencyPageWriter<'a> {
    store: &'a SourcePackFilesystemArtifactStore,
    target: SourcePackArtifactTarget,
    item_index: usize,
    work_item_count: usize,
    page_index: usize,
    first_dependency_position: usize,
    dependency_item_count: usize,
    dependency_item_ranges: Vec<SourcePackJobIndexRange>,
    seen_dependency_item_indices: BTreeSet<usize>,
    current_dependency_item_indices: Vec<usize>,
}

impl<'a> SourcePackWorkQueueDependencyPageWriter<'a> {
    fn new(
        store: &'a SourcePackFilesystemArtifactStore,
        target: SourcePackArtifactTarget,
        item_index: usize,
        work_item_count: usize,
    ) -> Self {
        Self {
            store,
            target,
            item_index,
            work_item_count,
            page_index: 0,
            first_dependency_position: 0,
            dependency_item_count: 0,
            dependency_item_ranges: Vec::new(),
            seen_dependency_item_indices: BTreeSet::new(),
            current_dependency_item_indices: Vec::with_capacity(
                SOURCE_PACK_WORK_QUEUE_DEPENDENCIES_DEFAULT_PAGE_SIZE,
            ),
        }
    }

    fn push(&mut self, dependency_item_index: usize) -> Result<(), CompileError> {
        self.push_impl(dependency_item_index, true)
    }

    fn push_impl(
        &mut self,
        dependency_item_index: usize,
        record_reverse_dependent: bool,
    ) -> Result<(), CompileError> {
        if dependency_item_index >= self.item_index {
            return Err(source_pack_library_partition_contract_error(format!(
                "work queue page {} depends on non-prior item {}",
                self.item_index, dependency_item_index
            )));
        }
        if self.dependency_item_ranges.iter().any(|range| {
            range
                .iter()
                .is_some_and(|indices| indices.contains(&dependency_item_index))
        }) {
            return Err(source_pack_library_partition_contract_error(format!(
                "work queue page {} contains duplicate ranged dependency item {}",
                self.item_index, dependency_item_index
            )));
        }
        if !self
            .seen_dependency_item_indices
            .insert(dependency_item_index)
        {
            return Err(source_pack_library_partition_contract_error(format!(
                "work queue page {} contains duplicate dependency item {}",
                self.item_index, dependency_item_index
            )));
        }
        self.current_dependency_item_indices
            .push(dependency_item_index);
        if self.current_dependency_item_indices.len()
            == SOURCE_PACK_WORK_QUEUE_DEPENDENCIES_DEFAULT_PAGE_SIZE
        {
            self.flush()?;
        }
        if record_reverse_dependent {
            source_pack_work_queue_append_dependent_page(
                self.store,
                self.target,
                dependency_item_index,
                self.item_index,
                self.work_item_count,
            )?;
        }
        Ok(())
    }

    fn flush(&mut self) -> Result<(), CompileError> {
        if self.current_dependency_item_indices.is_empty() {
            return Ok(());
        }
        let dependency_item_indices = std::mem::take(&mut self.current_dependency_item_indices);
        let dependency_page = SourcePackWorkQueueDependenciesPage {
            version: SOURCE_PACK_WORK_QUEUE_DEPENDENCIES_PAGE_VERSION,
            target: self.target,
            item_index: self.item_index,
            page_index: self.page_index,
            first_dependency_position: self.first_dependency_position,
            dependency_count: dependency_item_indices.len(),
            dependency_item_indices,
        };
        validate_source_pack_work_queue_dependencies_page(
            &dependency_page,
            self.target,
            self.item_index,
            self.page_index,
        )?;
        self.store
            .store_work_queue_dependencies_page(&dependency_page)?;
        self.dependency_item_count = self
            .dependency_item_count
            .saturating_add(dependency_page.dependency_count);
        self.first_dependency_position = self
            .first_dependency_position
            .saturating_add(dependency_page.dependency_count);
        self.page_index += 1;
        Ok(())
    }

    fn push_range(
        &mut self,
        first_item_index: usize,
        item_count: usize,
    ) -> Result<(), CompileError> {
        self.push_range_impl(first_item_index, item_count, true)
    }

    fn push_range_impl(
        &mut self,
        first_item_index: usize,
        item_count: usize,
        record_reverse_dependents: bool,
    ) -> Result<(), CompileError> {
        if item_count == 0 {
            return Ok(());
        }
        let end_item_index = first_item_index.checked_add(item_count).ok_or_else(|| {
            source_pack_library_partition_contract_error(format!(
                "work queue page {} dependency item range {}+{} overflows",
                self.item_index, first_item_index, item_count
            ))
        })?;
        if end_item_index > self.item_index {
            return Err(source_pack_library_partition_contract_error(format!(
                "work queue page {} depends on non-prior item range {}..{}",
                self.item_index, first_item_index, end_item_index
            )));
        }
        if let Some(duplicate) = self
            .seen_dependency_item_indices
            .range(first_item_index..end_item_index)
            .next()
        {
            return Err(source_pack_library_partition_contract_error(format!(
                "work queue page {} dependency range {}..{} duplicates explicit dependency item {}",
                self.item_index, first_item_index, end_item_index, duplicate
            )));
        }
        if source_pack_try_push_dependency_item_range(
            &mut self.dependency_item_ranges,
            self.item_index,
            first_item_index,
            item_count,
        )? {
            if record_reverse_dependents {
                source_pack_append_work_queue_dependent_range_to_dependency_range(
                    self.store,
                    self.target,
                    first_item_index,
                    item_count,
                    self.item_index,
                    1,
                    self.work_item_count,
                )?;
            }
            return Ok(());
        }

        for dependency_item_index in first_item_index..end_item_index {
            self.push_impl(dependency_item_index, record_reverse_dependents)?;
        }
        Ok(())
    }

    fn finish(mut self) -> Result<(usize, usize, Vec<SourcePackJobIndexRange>), CompileError> {
        self.flush()?;
        Ok((
            self.dependency_item_count,
            self.page_index,
            self.dependency_item_ranges,
        ))
    }
}

fn source_pack_try_push_dependency_item_range(
    dependency_item_ranges: &mut Vec<SourcePackJobIndexRange>,
    item_index: usize,
    first_item_index: usize,
    item_count: usize,
) -> Result<bool, CompileError> {
    let end_item_index = first_item_index.checked_add(item_count).ok_or_else(|| {
        source_pack_library_partition_contract_error(format!(
            "work queue page {item_index} dependency item range {first_item_index}+{item_count} overflows"
        ))
    })?;
    if end_item_index > item_index {
        return Err(source_pack_library_partition_contract_error(format!(
            "work queue page {item_index} depends on non-prior item range {first_item_index}..{end_item_index}"
        )));
    }

    let mut merged_ranges = dependency_item_ranges.clone();
    merged_ranges.push(SourcePackJobIndexRange {
        first_job_index: first_item_index,
        job_count: item_count,
    });
    merged_ranges.sort_by_key(|range| range.first_job_index);

    let mut compact_ranges = Vec::<SourcePackJobIndexRange>::with_capacity(merged_ranges.len());
    for range in merged_ranges {
        let Some(range_end) = range.end_job_index() else {
            return Err(source_pack_library_partition_contract_error(format!(
                "work queue page {item_index} dependency item range starting at {} overflows",
                range.first_job_index
            )));
        };
        if let Some(last) = compact_ranges.last_mut() {
            let Some(last_end) = last.end_job_index() else {
                return Err(source_pack_library_partition_contract_error(format!(
                    "work queue page {item_index} dependency item range starting at {} overflows",
                    last.first_job_index
                )));
            };
            if range.first_job_index <= last_end {
                let compact_end = last_end.max(range_end);
                last.job_count = compact_end - last.first_job_index;
                continue;
            }
        }
        compact_ranges.push(range);
    }

    if compact_ranges.len() > SOURCE_PACK_WORK_QUEUE_DEPENDENCIES_DEFAULT_PAGE_SIZE {
        return Ok(false);
    }
    *dependency_item_ranges = compact_ranges;
    Ok(true)
}

fn source_pack_try_push_dependent_item_range(
    dependent_item_ranges: &mut Vec<SourcePackJobIndexRange>,
    item_index: usize,
    first_item_index: usize,
    item_count: usize,
) -> Result<bool, CompileError> {
    let end_item_index = first_item_index.checked_add(item_count).ok_or_else(|| {
        source_pack_library_partition_contract_error(format!(
            "work queue page {item_index} dependent item range {first_item_index}+{item_count} overflows"
        ))
    })?;
    if first_item_index <= item_index {
        return Err(source_pack_library_partition_contract_error(format!(
            "work queue page {item_index} has non-later dependent item range {first_item_index}..{end_item_index}"
        )));
    }

    let mut merged_ranges = dependent_item_ranges.clone();
    merged_ranges.push(SourcePackJobIndexRange {
        first_job_index: first_item_index,
        job_count: item_count,
    });
    merged_ranges.sort_by_key(|range| range.first_job_index);

    let mut compact_ranges = Vec::<SourcePackJobIndexRange>::with_capacity(merged_ranges.len());
    for range in merged_ranges {
        let Some(range_end) = range.end_job_index() else {
            return Err(source_pack_library_partition_contract_error(format!(
                "work queue page {item_index} dependent item range starting at {} overflows",
                range.first_job_index
            )));
        };
        if let Some(last) = compact_ranges.last_mut() {
            let Some(last_end) = last.end_job_index() else {
                return Err(source_pack_library_partition_contract_error(format!(
                    "work queue page {item_index} dependent item range starting at {} overflows",
                    last.first_job_index
                )));
            };
            if range.first_job_index <= last_end {
                let compact_end = last_end.max(range_end);
                last.job_count = compact_end - last.first_job_index;
                continue;
            }
        }
        compact_ranges.push(range);
    }

    if compact_ranges.len() > SOURCE_PACK_WORK_QUEUE_DEPENDENTS_DEFAULT_PAGE_SIZE {
        return Ok(false);
    }
    *dependent_item_ranges = compact_ranges;
    Ok(true)
}

fn store_source_pack_work_queue_page_with_dependency_writer<F>(
    store: &SourcePackFilesystemArtifactStore,
    page: &SourcePackWorkQueuePage,
    work_item_count: usize,
    mut write_dependencies: F,
) -> Result<SourcePackWorkQueuePage, CompileError>
where
    F: FnMut(&mut SourcePackWorkQueueDependencyPageWriter<'_>) -> Result<(), CompileError>,
{
    validate_source_pack_work_queue_page(page, page.target, Some(page.item_index))?;
    if page.item_index >= work_item_count {
        return Err(source_pack_library_partition_contract_error(format!(
            "stored work queue page {} exceeds item count {}",
            page.item_index, work_item_count
        )));
    }
    let mut writer = SourcePackWorkQueueDependencyPageWriter::new(
        store,
        page.target,
        page.item_index,
        work_item_count,
    );
    write_dependencies(&mut writer)?;
    let (dependency_item_count, dependency_page_count, dependency_item_ranges) = writer.finish()?;
    let mut stored_page = page.clone();
    stored_page.dependency_item_indices.clear();
    stored_page.dependency_item_count = dependency_item_count;
    stored_page.dependency_page_count = dependency_page_count;
    stored_page.dependency_item_ranges = dependency_item_ranges;
    stored_page.dependent_item_indices.clear();
    stored_page.dependent_item_count = 0;
    stored_page.dependent_page_count = 0;
    stored_page.dependent_item_ranges.clear();
    validate_source_pack_work_queue_page(&stored_page, page.target, Some(page.item_index))?;
    store.store_work_queue_page(&stored_page)?;
    Ok(stored_page)
}

#[cfg(test)]
struct SourcePackInitialWorkQueueProgressPageWriter<'a> {
    store: &'a SourcePackFilesystemArtifactStore,
    target: SourcePackArtifactTarget,
    work_item_count: usize,
    page_size: usize,
    next_item_index: usize,
    current_page_index: usize,
    current_first_item_index: usize,
    current_artifact_item_indices: Vec<usize>,
    current_ready_item_indices: Vec<usize>,
    current_ready_artifact_item_indices: Vec<usize>,
    current_remaining_dependency_counts: Vec<SourcePackWorkQueueRemainingDependencyCount>,
    current_remaining_dependent_counts: Vec<SourcePackWorkQueueRemainingDependentCount>,
    artifact_item_count: usize,
    ready_item_count: usize,
    ready_artifact_item_count: usize,
    first_ready_item_index: Option<usize>,
    first_ready_artifact_item_index: Option<usize>,
}

#[cfg(test)]
impl<'a> SourcePackInitialWorkQueueProgressPageWriter<'a> {
    fn new(
        store: &'a SourcePackFilesystemArtifactStore,
        target: SourcePackArtifactTarget,
        work_item_count: usize,
        page_size: usize,
    ) -> Self {
        Self {
            store,
            target,
            work_item_count,
            page_size: page_size.max(1),
            next_item_index: 0,
            current_page_index: 0,
            current_first_item_index: 0,
            current_artifact_item_indices: Vec::new(),
            current_ready_item_indices: Vec::new(),
            current_ready_artifact_item_indices: Vec::new(),
            current_remaining_dependency_counts: Vec::new(),
            current_remaining_dependent_counts: Vec::new(),
            artifact_item_count: 0,
            ready_item_count: 0,
            ready_artifact_item_count: 0,
            first_ready_item_index: None,
            first_ready_artifact_item_index: None,
        }
    }

    fn record_item(&mut self, item: &SourcePackWorkQueuePage) -> Result<(), CompileError> {
        validate_source_pack_work_queue_page(item, self.target, Some(item.item_index))?;
        if item.item_index != self.next_item_index {
            return Err(source_pack_library_partition_contract_error(format!(
                "initial work queue progress expected item {} but saw {}",
                self.next_item_index, item.item_index
            )));
        }
        let dependency_count = source_pack_work_queue_page_dependency_count(item);
        let artifact_backed = source_pack_work_queue_item_kind_is_artifact_backed(item.kind);
        if artifact_backed {
            self.current_artifact_item_indices.push(item.item_index);
            self.artifact_item_count = self.artifact_item_count.saturating_add(1);
        }
        if dependency_count == 0 {
            self.current_ready_item_indices.push(item.item_index);
            self.ready_item_count = self.ready_item_count.saturating_add(1);
            self.first_ready_item_index = self.first_ready_item_index.or(Some(item.item_index));
            if artifact_backed {
                self.current_ready_artifact_item_indices
                    .push(item.item_index);
                self.ready_artifact_item_count = self.ready_artifact_item_count.saturating_add(1);
                self.first_ready_artifact_item_index = self
                    .first_ready_artifact_item_index
                    .or(Some(item.item_index));
            }
        } else {
            self.current_remaining_dependency_counts.push(
                SourcePackWorkQueueRemainingDependencyCount {
                    item_index: item.item_index,
                    remaining_dependency_count: dependency_count,
                },
            );
        }
        let dependent_count = source_pack_work_queue_page_dependent_count(item);
        if dependent_count != 0 {
            self.current_remaining_dependent_counts.push(
                SourcePackWorkQueueRemainingDependentCount {
                    item_index: item.item_index,
                    remaining_dependent_count: dependent_count,
                },
            );
        }
        self.next_item_index += 1;
        if self.next_item_index == self.current_page_end_index() {
            self.flush_current_page()?;
        }
        Ok(())
    }

    fn finish(self) -> Result<SourcePackWorkQueueProgressIndex, CompileError> {
        if self.next_item_index != self.work_item_count {
            return Err(source_pack_library_partition_contract_error(format!(
                "initial work queue progress saw {} items but expected {}",
                self.next_item_index, self.work_item_count
            )));
        }
        if !self.current_ready_item_indices.is_empty() {
            return Err(source_pack_library_partition_contract_error(
                "initial work queue progress has unflushed ready items",
            ));
        }
        if !self.current_artifact_item_indices.is_empty() {
            return Err(source_pack_library_partition_contract_error(
                "initial work queue progress has unflushed artifact items",
            ));
        }
        if !self.current_ready_artifact_item_indices.is_empty() {
            return Err(source_pack_library_partition_contract_error(
                "initial work queue progress has unflushed ready artifact items",
            ));
        }
        if !self.current_remaining_dependency_counts.is_empty() {
            return Err(source_pack_library_partition_contract_error(
                "initial work queue progress has unflushed dependency counters",
            ));
        }
        if !self.current_remaining_dependent_counts.is_empty() {
            return Err(source_pack_library_partition_contract_error(
                "initial work queue progress has unflushed dependent counters",
            ));
        }
        let index = SourcePackWorkQueueProgressIndex {
            version: SOURCE_PACK_WORK_QUEUE_PROGRESS_INDEX_VERSION,
            target: self.target,
            work_item_count: self.work_item_count,
            page_size: self.page_size,
            page_count: self.work_item_count.div_ceil(self.page_size),
            artifact_item_count: self.artifact_item_count,
            completed_item_count: 0,
            ready_item_count: self.ready_item_count,
            ready_artifact_item_count: self.ready_artifact_item_count,
            claimed_item_count: 0,
            first_ready_item_index: self.first_ready_item_index,
            first_ready_artifact_item_index: self.first_ready_artifact_item_index,
        };
        validate_source_pack_work_queue_progress_index(&index, self.target)?;
        self.store
            .store_work_queue_progress_directory_pages_for_index(&index)?;
        self.store.store_work_queue_progress_index(&index)?;
        Ok(index)
    }

    fn current_page_item_count(&self) -> usize {
        self.page_size
            .min(self.work_item_count - self.current_first_item_index)
    }

    fn current_page_end_index(&self) -> usize {
        self.current_first_item_index + self.current_page_item_count()
    }

    fn flush_current_page(&mut self) -> Result<(), CompileError> {
        let item_count = self.current_page_item_count();
        let artifact_item_indices = std::mem::take(&mut self.current_artifact_item_indices);
        let ready_item_indices = std::mem::take(&mut self.current_ready_item_indices);
        let ready_artifact_item_indices =
            std::mem::take(&mut self.current_ready_artifact_item_indices);
        let remaining_dependency_counts =
            std::mem::take(&mut self.current_remaining_dependency_counts);
        let remaining_dependent_counts =
            std::mem::take(&mut self.current_remaining_dependent_counts);
        let page = SourcePackWorkQueueProgressPage {
            version: SOURCE_PACK_WORK_QUEUE_PROGRESS_PAGE_VERSION,
            target: self.target,
            page_index: self.current_page_index,
            first_item_index: self.current_first_item_index,
            item_count,
            artifact_item_indices,
            remaining_dependency_counts,
            remaining_dependent_counts,
            completed_item_indices: Vec::new(),
            ready_item_indices,
            ready_artifact_item_indices,
            claimed_items: Vec::new(),
        };
        validate_source_pack_work_queue_progress_page(
            &page,
            self.target,
            Some(self.current_page_index),
        )?;
        self.store.store_work_queue_progress_page(&page)?;
        self.current_page_index += 1;
        self.current_first_item_index = self.current_page_index * self.page_size;
        Ok(())
    }
}

#[cfg(test)]
fn store_initial_work_queue_progress_from_stored_work_queue_pages(
    store: &SourcePackFilesystemArtifactStore,
    target: SourcePackArtifactTarget,
    work_item_count: usize,
    page_size: usize,
) -> Result<SourcePackWorkQueueProgressIndex, CompileError> {
    let mut progress_writer = SourcePackInitialWorkQueueProgressPageWriter::new(
        store,
        target,
        work_item_count,
        page_size,
    );
    for item_index in 0..work_item_count {
        let item = store.load_work_queue_page_for_target(target, item_index)?;
        progress_writer.record_item(&item)?;
    }
    progress_writer.finish()
}

#[derive(Clone, Debug, PartialEq, Eq, Serialize, Deserialize)]
struct SourcePackInitialWorkQueueProgressPrepareProgress {
    version: u32,
    target: SourcePackArtifactTarget,
    work_item_count: usize,
    page_size: usize,
    page_count: usize,
    next_page_index: usize,
    artifact_item_count: usize,
    ready_item_count: usize,
    ready_artifact_item_count: usize,
    first_ready_item_index: Option<usize>,
    first_ready_artifact_item_index: Option<usize>,
}

fn validate_source_pack_initial_work_queue_progress_prepare_progress(
    progress: &SourcePackInitialWorkQueueProgressPrepareProgress,
    queue: &SourcePackWorkQueueIndex,
    page_size: usize,
) -> Result<(), CompileError> {
    validate_source_pack_work_queue_index(queue, queue.target)?;
    if progress.version != SOURCE_PACK_WORK_QUEUE_PROGRESS_PREPARE_PROGRESS_VERSION {
        return Err(CompileError::GpuFrontend(format!(
            "unsupported source-pack work queue progress prepare progress version {}; expected {}",
            progress.version, SOURCE_PACK_WORK_QUEUE_PROGRESS_PREPARE_PROGRESS_VERSION
        )));
    }
    if progress.target != queue.target {
        return Err(source_pack_library_partition_contract_error(format!(
            "work queue progress prepare target {:?} does not match queue target {:?}",
            progress.target, queue.target
        )));
    }
    if page_size == 0 {
        return Err(source_pack_library_partition_contract_error(
            "work queue progress prepare page_size is zero",
        ));
    }
    if page_size > SOURCE_PACK_WORK_QUEUE_PROGRESS_DEFAULT_PAGE_SIZE {
        return Err(source_pack_library_partition_contract_error(format!(
            "work queue progress prepare page_size {page_size} exceeds record cap {}",
            SOURCE_PACK_WORK_QUEUE_PROGRESS_DEFAULT_PAGE_SIZE
        )));
    }
    let page_count = queue.work_item_count.div_ceil(page_size);
    if progress.work_item_count != queue.work_item_count
        || progress.page_size != page_size
        || progress.page_count != page_count
    {
        return Err(source_pack_library_partition_contract_error(format!(
            "work queue progress prepare shape item/page-size/page-count {}/{}/{} does not match expected {}/{}/{}",
            progress.work_item_count,
            progress.page_size,
            progress.page_count,
            queue.work_item_count,
            page_size,
            page_count
        )));
    }
    if progress.next_page_index > progress.page_count {
        return Err(source_pack_library_partition_contract_error(format!(
            "work queue progress prepare next page {} exceeds page count {}",
            progress.next_page_index, progress.page_count
        )));
    }
    if progress.artifact_item_count > queue.artifact_item_count
        || progress.ready_item_count > queue.work_item_count
        || progress.ready_artifact_item_count > progress.ready_item_count
        || progress.ready_artifact_item_count > progress.artifact_item_count
    {
        return Err(source_pack_library_partition_contract_error(format!(
            "work queue progress prepare counts artifact/ready/ready-artifact {}/{}/{} exceed queue item counts {}/{}",
            progress.artifact_item_count,
            progress.ready_item_count,
            progress.ready_artifact_item_count,
            queue.artifact_item_count,
            queue.work_item_count
        )));
    }
    if let Some(first_ready_item_index) = progress.first_ready_item_index {
        if first_ready_item_index >= queue.work_item_count || progress.ready_item_count == 0 {
            return Err(source_pack_library_partition_contract_error(format!(
                "work queue progress prepare first ready item {first_ready_item_index} is invalid"
            )));
        }
    } else if progress.ready_item_count != 0 {
        return Err(source_pack_library_partition_contract_error(format!(
            "work queue progress prepare has {} ready items but no first ready item",
            progress.ready_item_count
        )));
    }
    if let Some(first_ready_artifact_item_index) = progress.first_ready_artifact_item_index {
        if first_ready_artifact_item_index >= queue.work_item_count
            || progress.ready_artifact_item_count == 0
        {
            return Err(source_pack_library_partition_contract_error(format!(
                "work queue progress prepare first ready artifact item {first_ready_artifact_item_index} is invalid"
            )));
        }
    } else if progress.ready_artifact_item_count != 0 {
        return Err(source_pack_library_partition_contract_error(format!(
            "work queue progress prepare has {} ready artifact items but no first ready artifact item",
            progress.ready_artifact_item_count
        )));
    }
    Ok(())
}

fn source_pack_initial_work_queue_progress_index_from_prepare_progress(
    progress: &SourcePackInitialWorkQueueProgressPrepareProgress,
) -> SourcePackWorkQueueProgressIndex {
    SourcePackWorkQueueProgressIndex {
        version: SOURCE_PACK_WORK_QUEUE_PROGRESS_INDEX_VERSION,
        target: progress.target,
        work_item_count: progress.work_item_count,
        page_size: progress.page_size,
        page_count: progress.page_count,
        artifact_item_count: progress.artifact_item_count,
        completed_item_count: 0,
        ready_item_count: progress.ready_item_count,
        ready_artifact_item_count: progress.ready_artifact_item_count,
        claimed_item_count: 0,
        first_ready_item_index: progress.first_ready_item_index,
        first_ready_artifact_item_index: progress.first_ready_artifact_item_index,
    }
}

fn source_pack_update_initial_work_queue_progress_prepare_progress_from_page(
    progress: &mut SourcePackInitialWorkQueueProgressPrepareProgress,
    page: &SourcePackWorkQueueProgressPage,
) -> Result<(), CompileError> {
    validate_source_pack_work_queue_progress_page(page, progress.target, Some(page.page_index))?;
    if page.page_index != progress.next_page_index {
        return Err(source_pack_library_partition_contract_error(format!(
            "work queue progress prepare expected page {} but saw {}",
            progress.next_page_index, page.page_index
        )));
    }
    let summary = source_pack_work_queue_progress_page_summary(page);
    progress.artifact_item_count = progress
        .artifact_item_count
        .saturating_add(summary.artifact_item_count);
    progress.ready_item_count = progress
        .ready_item_count
        .saturating_add(summary.ready_item_count);
    progress.ready_artifact_item_count = progress
        .ready_artifact_item_count
        .saturating_add(summary.ready_artifact_item_count);
    progress.first_ready_item_index = progress
        .first_ready_item_index
        .or(summary.first_ready_item_index);
    progress.first_ready_artifact_item_index = progress
        .first_ready_artifact_item_index
        .or(summary.first_ready_artifact_item_index);
    progress.next_page_index = progress.next_page_index.checked_add(1).ok_or_else(|| {
        source_pack_library_partition_contract_error(
            "work queue progress prepare next page index overflows",
        )
    })?;
    Ok(())
}

fn source_pack_initial_work_queue_progress_page_from_stored_work_queue_pages(
    store: &SourcePackFilesystemArtifactStore,
    target: SourcePackArtifactTarget,
    page_index: usize,
    page_size: usize,
    work_item_count: usize,
) -> Result<SourcePackWorkQueueProgressPage, CompileError> {
    if page_size == 0 || page_size > SOURCE_PACK_WORK_QUEUE_PROGRESS_DEFAULT_PAGE_SIZE {
        return Err(source_pack_library_partition_contract_error(format!(
            "work queue progress page_size {page_size} exceeds bounds 1..={}",
            SOURCE_PACK_WORK_QUEUE_PROGRESS_DEFAULT_PAGE_SIZE
        )));
    }
    let first_item_index = page_index.checked_mul(page_size).ok_or_else(|| {
        source_pack_library_partition_contract_error(format!(
            "work queue progress page {page_index} first item index overflows"
        ))
    })?;
    if first_item_index >= work_item_count {
        return Err(source_pack_library_partition_contract_error(format!(
            "work queue progress page {page_index} starts at {first_item_index} but work item count is {work_item_count}"
        )));
    }
    let item_count = page_size.min(work_item_count - first_item_index);
    let mut artifact_item_indices = Vec::new();
    let mut ready_item_indices = Vec::new();
    let mut ready_artifact_item_indices = Vec::new();
    let mut remaining_dependency_counts = Vec::new();
    let mut remaining_dependent_counts = Vec::new();
    let item_end = first_item_index + item_count;
    for item_index in first_item_index..item_end {
        let item = store.load_work_queue_page_for_target(target, item_index)?;
        validate_source_pack_work_queue_page(&item, target, Some(item_index))?;
        let artifact_backed = source_pack_work_queue_item_kind_is_artifact_backed(item.kind);
        if artifact_backed {
            artifact_item_indices.push(item_index);
        }
        let dependency_count = source_pack_work_queue_page_dependency_count(&item);
        if dependency_count == 0 {
            ready_item_indices.push(item_index);
            if artifact_backed {
                ready_artifact_item_indices.push(item_index);
            }
        } else {
            remaining_dependency_counts.push(SourcePackWorkQueueRemainingDependencyCount {
                item_index,
                remaining_dependency_count: dependency_count,
            });
        }
        let dependent_count = source_pack_work_queue_page_dependent_count(&item);
        if dependent_count != 0 {
            remaining_dependent_counts.push(SourcePackWorkQueueRemainingDependentCount {
                item_index,
                remaining_dependent_count: dependent_count,
            });
        }
    }
    let page = SourcePackWorkQueueProgressPage {
        version: SOURCE_PACK_WORK_QUEUE_PROGRESS_PAGE_VERSION,
        target,
        page_index,
        first_item_index,
        item_count,
        artifact_item_indices,
        remaining_dependency_counts,
        remaining_dependent_counts,
        completed_item_indices: Vec::new(),
        ready_item_indices,
        ready_artifact_item_indices,
        claimed_items: Vec::new(),
    };
    validate_source_pack_work_queue_progress_page(&page, target, Some(page_index))?;
    Ok(page)
}

fn source_pack_store_initial_work_queue_progress_directory_pages_after_progress_page(
    store: &SourcePackFilesystemArtifactStore,
    index: &SourcePackWorkQueueProgressIndex,
    progress_page_index: usize,
) -> Result<(), CompileError> {
    validate_source_pack_work_queue_progress_index(index, index.target)?;
    let directory_page_index =
        source_pack_work_queue_progress_directory_page_index_for_progress_page(progress_page_index);
    let (first_progress_page_index, progress_page_count) =
        source_pack_work_queue_progress_directory_page_range(index, directory_page_index)?;
    if progress_page_index + 1 != first_progress_page_index + progress_page_count {
        return Ok(());
    }
    let directory_page = source_pack_work_queue_progress_directory_page_from_summaries(
        store,
        index.target,
        index,
        &[],
        directory_page_index,
    )?;
    store.store_work_queue_progress_directory_page_for_target(index.target, &directory_page)?;

    let directory_index_page_index =
        source_pack_work_queue_progress_directory_index_page_index_for_directory_page(
            directory_page_index,
        );
    let (first_directory_page_index, directory_page_count) =
        source_pack_work_queue_progress_directory_index_page_range(
            index,
            directory_index_page_index,
        )?;
    if directory_page_index + 1 != first_directory_page_index + directory_page_count {
        return Ok(());
    }
    let directory_index_page =
        source_pack_work_queue_progress_directory_index_page_from_directory_pages(
            store,
            index.target,
            index,
            &[],
            directory_index_page_index,
        )?;
    store.store_work_queue_progress_directory_index_page_for_target(
        index.target,
        &directory_index_page,
        index,
    )?;
    Ok(())
}

fn store_initial_work_queue_progress_from_stored_work_queue_pages_chunk(
    store: &SourcePackFilesystemArtifactStore,
    queue: &SourcePackWorkQueueIndex,
    page_size: usize,
    max_new_pages: usize,
) -> Result<SourcePackFilesystemWorkQueueProgressPrepareStepResult, CompileError> {
    if max_new_pages == 0 {
        return Err(CompileError::GpuFrontend(
            "source-pack work queue progress chunk max_new_pages must be greater than zero".into(),
        ));
    }
    validate_source_pack_work_queue_index(queue, queue.target)?;
    if page_size == 0 {
        return Err(CompileError::GpuFrontend(
            "source-pack work queue progress chunk page_size must be greater than zero".into(),
        ));
    }
    if page_size > SOURCE_PACK_WORK_QUEUE_PROGRESS_DEFAULT_PAGE_SIZE {
        return Err(source_pack_library_partition_contract_error(format!(
            "source-pack work queue progress chunk page_size {page_size} exceeds record cap {}",
            SOURCE_PACK_WORK_QUEUE_PROGRESS_DEFAULT_PAGE_SIZE
        )));
    }
    let page_count = queue.work_item_count.div_ceil(page_size);
    if store
        .work_queue_progress_index_path_for_target(queue.target)
        .is_file()
    {
        let index = store.load_work_queue_progress_index_for_target(queue.target)?;
        return Ok(SourcePackFilesystemWorkQueueProgressPrepareStepResult {
            target: queue.target,
            complete: true,
            work_item_count: index.work_item_count,
            page_size: index.page_size,
            page_count: index.page_count,
            next_page_index: index.page_count,
            new_progress_page_count: 0,
            artifact_item_count: index.artifact_item_count,
            ready_item_count: index.ready_item_count,
            ready_artifact_item_count: index.ready_artifact_item_count,
            first_ready_item_index: index.first_ready_item_index,
            first_ready_artifact_item_index: index.first_ready_artifact_item_index,
            work_queue_progress_index_path: Some(
                store.work_queue_progress_index_path_for_target(queue.target),
            ),
        });
    }

    let progress_path = store.work_queue_progress_prepare_progress_path_for_target(queue.target);
    let mut progress = if progress_path.is_file() {
        source_pack_load_initial_work_queue_progress_prepare_progress(store, queue, page_size)?
    } else {
        SourcePackInitialWorkQueueProgressPrepareProgress {
            version: SOURCE_PACK_WORK_QUEUE_PROGRESS_PREPARE_PROGRESS_VERSION,
            target: queue.target,
            work_item_count: queue.work_item_count,
            page_size,
            page_count,
            next_page_index: 0,
            artifact_item_count: 0,
            ready_item_count: 0,
            ready_artifact_item_count: 0,
            first_ready_item_index: None,
            first_ready_artifact_item_index: None,
        }
    };
    validate_source_pack_initial_work_queue_progress_prepare_progress(&progress, queue, page_size)?;

    let mut new_progress_page_count = 0usize;
    while progress.next_page_index < page_count && new_progress_page_count < max_new_pages {
        let progress_page =
            source_pack_initial_work_queue_progress_page_from_stored_work_queue_pages(
                store,
                queue.target,
                progress.next_page_index,
                page_size,
                queue.work_item_count,
            )?;
        store.store_work_queue_progress_page(&progress_page)?;
        source_pack_update_initial_work_queue_progress_prepare_progress_from_page(
            &mut progress,
            &progress_page,
        )?;
        let progress_index =
            source_pack_initial_work_queue_progress_index_from_prepare_progress(&progress);
        source_pack_store_initial_work_queue_progress_directory_pages_after_progress_page(
            store,
            &progress_index,
            progress_page.page_index,
        )?;
        source_pack_store_initial_work_queue_progress_prepare_progress(store, &progress)?;
        new_progress_page_count = new_progress_page_count.checked_add(1).ok_or_else(|| {
            source_pack_library_partition_contract_error(
                "work queue progress chunk new page count overflows",
            )
        })?;
    }

    let mut work_queue_progress_index_path = None;
    if progress.next_page_index == page_count {
        if progress.artifact_item_count != queue.artifact_item_count {
            return Err(source_pack_library_partition_contract_error(format!(
                "work queue progress prepared {} artifact-backed items but queue index records {}",
                progress.artifact_item_count, queue.artifact_item_count
            )));
        }
        let index = source_pack_initial_work_queue_progress_index_from_prepare_progress(&progress);
        validate_source_pack_work_queue_progress_index(&index, queue.target)?;
        work_queue_progress_index_path = Some(store.store_work_queue_progress_index(&index)?);
    }

    Ok(SourcePackFilesystemWorkQueueProgressPrepareStepResult {
        target: queue.target,
        complete: work_queue_progress_index_path.is_some(),
        work_item_count: progress.work_item_count,
        page_size: progress.page_size,
        page_count: progress.page_count,
        next_page_index: progress.next_page_index,
        new_progress_page_count,
        artifact_item_count: progress.artifact_item_count,
        ready_item_count: progress.ready_item_count,
        ready_artifact_item_count: progress.ready_artifact_item_count,
        first_ready_item_index: progress.first_ready_item_index,
        first_ready_artifact_item_index: progress.first_ready_artifact_item_index,
        work_queue_progress_index_path,
    })
}

fn source_pack_store_initial_work_queue_progress_prepare_progress(
    store: &SourcePackFilesystemArtifactStore,
    progress: &SourcePackInitialWorkQueueProgressPrepareProgress,
) -> Result<PathBuf, CompileError> {
    let queue_shape = SourcePackWorkQueueIndex {
        version: SOURCE_PACK_WORK_QUEUE_INDEX_VERSION,
        target: progress.target,
        work_item_count: progress.work_item_count,
        artifact_item_count: progress.artifact_item_count,
        final_item_index: progress.work_item_count.saturating_sub(1),
        final_job_index: progress.work_item_count.saturating_sub(1),
    };
    validate_source_pack_initial_work_queue_progress_prepare_progress(
        progress,
        &queue_shape,
        progress.page_size,
    )?;
    let path = store.work_queue_progress_prepare_progress_path_for_target(progress.target);
    let bytes = serde_json::to_vec_pretty(progress).map_err(|err| {
        CompileError::GpuFrontend(format!(
            "serialize source-pack work queue progress prepare progress: {err}"
        ))
    })?;
    write_source_pack_filesystem_file_atomically(
        &path,
        &bytes,
        "source-pack work queue progress prepare progress",
    )?;
    Ok(path)
}

fn source_pack_load_initial_work_queue_progress_prepare_progress(
    store: &SourcePackFilesystemArtifactStore,
    queue: &SourcePackWorkQueueIndex,
    page_size: usize,
) -> Result<SourcePackInitialWorkQueueProgressPrepareProgress, CompileError> {
    let path = store.work_queue_progress_prepare_progress_path_for_target(queue.target);
    let bytes = fs::read(&path).map_err(|err| {
        CompileError::GpuFrontend(format!(
            "read source-pack work queue progress prepare progress {}: {err}",
            path.display()
        ))
    })?;
    let progress =
        serde_json::from_slice::<SourcePackInitialWorkQueueProgressPrepareProgress>(&bytes)
            .map_err(|err| {
                CompileError::GpuFrontend(format!(
                    "parse source-pack work queue progress prepare progress {}: {err}",
                    path.display()
                ))
            })?;
    validate_source_pack_initial_work_queue_progress_prepare_progress(&progress, queue, page_size)?;
    Ok(progress)
}

fn store_source_pack_work_queue_compact_index(
    store: &SourcePackFilesystemArtifactStore,
    index: &SourcePackWorkQueueIndex,
) -> Result<PathBuf, CompileError> {
    validate_source_pack_work_queue_index(index, index.target)?;
    let path = store.work_queue_index_path_for_target(index.target);
    let bytes = serde_json::to_vec_pretty(index).map_err(|err| {
        CompileError::GpuFrontend(format!("serialize source-pack work queue index: {err}"))
    })?;
    write_source_pack_filesystem_file_atomically(&path, &bytes, "source-pack work queue index")?;
    Ok(path)
}

#[cfg(test)]
fn source_pack_insert_work_queue_page(
    pages: &mut [Option<SourcePackWorkQueuePage>],
    page: SourcePackWorkQueuePage,
) -> Result<(), CompileError> {
    validate_source_pack_work_queue_page(&page, page.target, Some(page.item_index))?;
    let Some(slot) = pages.get_mut(page.item_index) else {
        return Err(source_pack_library_partition_contract_error(format!(
            "work queue item {} exceeds page capacity {}",
            page.item_index,
            pages.len()
        )));
    };
    if slot.is_some() {
        return Err(source_pack_library_partition_contract_error(format!(
            "work queue item {} appears more than once",
            page.item_index
        )));
    }
    *slot = Some(page);
    Ok(())
}

#[cfg(test)]
fn source_pack_work_queue_dependents_by_item(
    pages: &[SourcePackWorkQueuePage],
) -> Result<Vec<Vec<usize>>, CompileError> {
    let mut dependents_by_item = vec![Vec::new(); pages.len()];
    for page in pages {
        if page.item_index >= pages.len() {
            return Err(source_pack_library_partition_contract_error(format!(
                "work queue item {} exceeds page count {}",
                page.item_index,
                pages.len()
            )));
        }
        for &dependency_item_index in &page.dependency_item_indices {
            let Some(dependents) = dependents_by_item.get_mut(dependency_item_index) else {
                return Err(source_pack_library_partition_contract_error(format!(
                    "work queue item {} depends on missing item {}",
                    page.item_index, dependency_item_index
                )));
            };
            dependents.push(page.item_index);
        }
        for range in &page.dependency_item_ranges {
            let Some(indices) = range.iter() else {
                return Err(source_pack_library_partition_contract_error(format!(
                    "work queue item {} dependency range starting at {} overflows",
                    page.item_index, range.first_job_index
                )));
            };
            for dependency_item_index in indices {
                let Some(dependents) = dependents_by_item.get_mut(dependency_item_index) else {
                    return Err(source_pack_library_partition_contract_error(format!(
                        "work queue item {} depends on missing ranged item {}",
                        page.item_index, dependency_item_index
                    )));
                };
                dependents.push(page.item_index);
            }
        }
    }
    for dependents in &mut dependents_by_item {
        dependents.sort_unstable();
        dependents.dedup();
    }
    Ok(dependents_by_item)
}

#[cfg(test)]
#[derive(Clone, Debug, PartialEq, Eq)]
struct SourcePackBuildArtifactPageMetadata {
    artifact_count: usize,
    scheduled_job_count: usize,
    link_interface_batches: Vec<SourcePackLinkInterfaceBatch>,
    link_object_batches: Vec<SourcePackLinkObjectBatch>,
    output_refs: SourcePackLibraryScheduleOutputRefs,
}

#[cfg(test)]
fn source_pack_build_artifact_page_metadata(
    schedule_index: &SourcePackLibraryScheduleIndex,
    schedule_pages: &[SourcePackLibrarySchedulePage],
    batch_limits: SourcePackJobBatchLimits,
) -> Result<SourcePackBuildArtifactPageMetadata, CompileError> {
    let job_schedule =
        source_pack_job_schedule_from_library_schedule_pages(schedule_index, schedule_pages)?;
    let output_refs = source_pack_library_schedule_output_refs(schedule_index, schedule_pages)?;
    let link_interface_batches = source_pack_link_interface_batches_from_output_refs(
        output_refs.interface_refs_by_job_index.values(),
        &output_refs.source_metadata_by_artifact_index,
        batch_limits,
    )?;
    let link_object_batches = source_pack_link_object_batches_from_output_refs(
        output_refs.object_refs_by_job_index.values(),
        &output_refs.source_metadata_by_artifact_index,
        batch_limits,
    )?;
    let scheduled_job_count = job_schedule.jobs.len();
    Ok(SourcePackBuildArtifactPageMetadata {
        artifact_count: schedule_index.job_count,
        scheduled_job_count,
        link_interface_batches,
        link_object_batches,
        output_refs,
    })
}

#[cfg(test)]
fn store_source_pack_build_job_batch_pages_from_stored_schedule_pages(
    store: &SourcePackFilesystemArtifactStore,
    schedule_index: &SourcePackLibraryScheduleIndex,
    batch_limits: SourcePackJobBatchLimits,
) -> Result<SourcePackStoredJobBatchPagesPrepareResult, CompileError> {
    validate_source_pack_library_schedule_index(schedule_index, schedule_index.target)?;
    let mut builder = SourcePackStoredJobBatchBuilder::new(batch_limits);
    let mut store_batch = |batch_jobs: Vec<SourcePackJob>,
                           batch_index: usize,
                           wave_index: usize,
                           source_bytes: usize,
                           source_file_count: usize,
                           source_lines: usize,
                           oversized: bool|
     -> Result<SourcePackJobBatchDependency, CompileError> {
        store_source_pack_stored_job_batch_page(
            store,
            schedule_index,
            batch_jobs,
            batch_index,
            wave_index,
            source_bytes,
            source_file_count,
            source_lines,
            oversized,
        )
    };

    let mut batch_count = 0usize;
    let mut dependency_edge_count = 0usize;
    for job_index in 0..schedule_index.job_count {
        let job = source_pack_stored_schedule_job_metadata(store, schedule_index, job_index)?;
        if let Some(dependency) = builder.push(job, &mut store_batch)? {
            dependency_edge_count =
                dependency_edge_count.saturating_add(dependency.dependency_count());
            batch_count += 1;
        }
    }
    if let Some(dependency) = builder.finish(&mut store_batch)? {
        dependency_edge_count = dependency_edge_count.saturating_add(dependency.dependency_count());
        batch_count += 1;
    }
    if batch_count == 0 {
        return Err(source_pack_artifact_shard_contract_error(
            "stored job-batch planner produced no batches",
        ));
    }

    let index = SourcePackBuildJobBatchPageIndex {
        version: SOURCE_PACK_BUILD_JOB_BATCH_PAGE_INDEX_VERSION,
        target: schedule_index.target,
        batch_count,
        scheduled_job_count: schedule_index.job_count,
        dependency_edge_count,
    };
    validate_source_pack_build_job_batch_page_index(&index, schedule_index.target)?;
    store.store_build_job_batch_page_index(&index)?;
    Ok(SourcePackStoredJobBatchPagesPrepareResult { index })
}

fn store_source_pack_build_job_batch_pages_from_stored_schedule_pages_chunk(
    store: &SourcePackFilesystemArtifactStore,
    schedule_index: &SourcePackLibraryScheduleIndex,
    batch_limits: SourcePackJobBatchLimits,
    max_new_batches: usize,
) -> Result<SourcePackFilesystemJobBatchPrepareStepResult, CompileError> {
    if max_new_batches == 0 {
        return Err(CompileError::GpuFrontend(
            "source-pack job-batch chunk max_new_batches must be greater than zero".into(),
        ));
    }
    validate_source_pack_library_schedule_index(schedule_index, schedule_index.target)?;
    let batch_limits = batch_limits.normalized();
    if store
        .build_job_batch_index_path_for_target(schedule_index.target)
        .is_file()
    {
        let index = store.load_build_job_batch_page_index_for_target(schedule_index.target)?;
        return Ok(SourcePackFilesystemJobBatchPrepareStepResult {
            target: schedule_index.target,
            complete: true,
            scheduled_job_count: index.scheduled_job_count,
            batch_count: index.batch_count,
            new_batch_count: 0,
            dependency_edge_count: index.dependency_edge_count,
            next_job_index: index.scheduled_job_count,
            job_batch_index_path: Some(
                store.build_job_batch_index_path_for_target(schedule_index.target),
            ),
        });
    }

    let progress_path =
        store.build_job_batch_prepare_progress_path_for_target(schedule_index.target);
    let mut progress = if progress_path.is_file() {
        store.load_build_job_batch_prepare_progress_for_target(
            schedule_index.target,
            schedule_index.job_count,
            batch_limits,
        )?
    } else {
        SourcePackBuildJobBatchPrepareProgress {
            version: SOURCE_PACK_BUILD_JOB_BATCH_PREPARE_PROGRESS_VERSION,
            target: schedule_index.target,
            batch_limits,
            scheduled_job_count: schedule_index.job_count,
            next_job_index: 0,
            next_batch_index: 0,
            dependency_edge_count: 0,
        }
    };
    validate_source_pack_build_job_batch_prepare_progress(
        &progress,
        schedule_index.target,
        schedule_index.job_count,
        batch_limits,
    )?;

    let mut builder = SourcePackStoredJobBatchBuilder::new(batch_limits);
    builder.next_batch_index = progress.next_batch_index;
    let mut new_batch_count = 0usize;
    let mut store_batch = |batch_jobs: Vec<SourcePackJob>,
                           batch_index: usize,
                           wave_index: usize,
                           source_bytes: usize,
                           source_file_count: usize,
                           source_lines: usize,
                           oversized: bool|
     -> Result<SourcePackJobBatchDependency, CompileError> {
        store_source_pack_stored_job_batch_page(
            store,
            schedule_index,
            batch_jobs,
            batch_index,
            wave_index,
            source_bytes,
            source_file_count,
            source_lines,
            oversized,
        )
    };

    while progress.next_job_index < schedule_index.job_count {
        let job = source_pack_stored_schedule_job_metadata(
            store,
            schedule_index,
            progress.next_job_index,
        )?;
        if builder.should_flush_before(&job) {
            let dependency = builder.flush(&mut store_batch)?.ok_or_else(|| {
                source_pack_artifact_shard_contract_error(
                    "job-batch chunk had no pending jobs to flush",
                )
            })?;
            progress.next_batch_index = builder.next_batch_index;
            progress.dependency_edge_count = progress
                .dependency_edge_count
                .saturating_add(dependency.dependency_count());
            store.store_build_job_batch_prepare_progress(&progress)?;
            new_batch_count += 1;
            if new_batch_count >= max_new_batches {
                return Ok(SourcePackFilesystemJobBatchPrepareStepResult {
                    target: schedule_index.target,
                    complete: false,
                    scheduled_job_count: schedule_index.job_count,
                    batch_count: progress.next_batch_index,
                    new_batch_count,
                    dependency_edge_count: progress.dependency_edge_count,
                    next_job_index: progress.next_job_index,
                    job_batch_index_path: None,
                });
            }
        }
        builder.current_source_bytes = builder
            .current_source_bytes
            .saturating_add(job.source_bytes);
        builder.current_source_file_count = builder
            .current_source_file_count
            .saturating_add(job.source_file_count);
        builder.current_source_lines = builder
            .current_source_lines
            .saturating_add(job.source_lines);
        builder.current_jobs.push(job);
        progress.next_job_index += 1;
    }

    if !builder.current_jobs.is_empty() {
        let dependency = builder.flush(&mut store_batch)?.ok_or_else(|| {
            source_pack_artifact_shard_contract_error(
                "job-batch chunk had no final pending jobs to flush",
            )
        })?;
        progress.next_batch_index = builder.next_batch_index;
        progress.dependency_edge_count = progress
            .dependency_edge_count
            .saturating_add(dependency.dependency_count());
        store.store_build_job_batch_prepare_progress(&progress)?;
        new_batch_count += 1;
        if new_batch_count >= max_new_batches && progress.next_job_index < schedule_index.job_count
        {
            return Ok(SourcePackFilesystemJobBatchPrepareStepResult {
                target: schedule_index.target,
                complete: false,
                scheduled_job_count: schedule_index.job_count,
                batch_count: progress.next_batch_index,
                new_batch_count,
                dependency_edge_count: progress.dependency_edge_count,
                next_job_index: progress.next_job_index,
                job_batch_index_path: None,
            });
        }
    }

    if progress.next_job_index != schedule_index.job_count {
        return Err(source_pack_artifact_shard_contract_error(format!(
            "job-batch chunk stopped at job {} but schedule has {} jobs",
            progress.next_job_index, schedule_index.job_count
        )));
    }
    if progress.next_batch_index == 0 {
        return Err(source_pack_artifact_shard_contract_error(
            "stored job-batch chunk planner produced no batches",
        ));
    }
    let index = SourcePackBuildJobBatchPageIndex {
        version: SOURCE_PACK_BUILD_JOB_BATCH_PAGE_INDEX_VERSION,
        target: schedule_index.target,
        batch_count: progress.next_batch_index,
        scheduled_job_count: schedule_index.job_count,
        dependency_edge_count: progress.dependency_edge_count,
    };
    validate_source_pack_build_job_batch_page_index(&index, schedule_index.target)?;
    let job_batch_index_path = store.store_build_job_batch_page_index(&index)?;
    Ok(SourcePackFilesystemJobBatchPrepareStepResult {
        target: schedule_index.target,
        complete: true,
        scheduled_job_count: index.scheduled_job_count,
        batch_count: index.batch_count,
        new_batch_count,
        dependency_edge_count: index.dependency_edge_count,
        next_job_index: progress.next_job_index,
        job_batch_index_path: Some(job_batch_index_path),
    })
}

#[cfg(test)]
struct SourcePackStoredJobBatchPagesPrepareResult {
    index: SourcePackBuildJobBatchPageIndex,
}

#[derive(Clone, Debug, PartialEq, Eq, Serialize, Deserialize)]
struct SourcePackBuildJobBatchPrepareProgress {
    version: u32,
    target: SourcePackArtifactTarget,
    batch_limits: SourcePackJobBatchLimits,
    scheduled_job_count: usize,
    next_job_index: usize,
    next_batch_index: usize,
    dependency_edge_count: usize,
}

fn validate_source_pack_build_job_batch_prepare_progress(
    progress: &SourcePackBuildJobBatchPrepareProgress,
    target: SourcePackArtifactTarget,
    scheduled_job_count: usize,
    batch_limits: SourcePackJobBatchLimits,
) -> Result<(), CompileError> {
    if progress.version != SOURCE_PACK_BUILD_JOB_BATCH_PREPARE_PROGRESS_VERSION {
        return Err(CompileError::GpuFrontend(format!(
            "unsupported source-pack job-batch prepare progress version {}; expected {}",
            progress.version, SOURCE_PACK_BUILD_JOB_BATCH_PREPARE_PROGRESS_VERSION
        )));
    }
    if progress.target != target {
        return Err(source_pack_artifact_shard_contract_error(format!(
            "job-batch prepare progress target {:?} does not match requested target {:?}",
            progress.target, target
        )));
    }
    if progress.batch_limits != batch_limits.normalized() {
        return Err(source_pack_artifact_shard_contract_error(
            "job-batch prepare progress was created with different batch limits",
        ));
    }
    if progress.scheduled_job_count != scheduled_job_count {
        return Err(source_pack_artifact_shard_contract_error(format!(
            "job-batch prepare progress scheduled_job_count {} does not match schedule job_count {scheduled_job_count}",
            progress.scheduled_job_count
        )));
    }
    if progress.next_job_index > scheduled_job_count {
        return Err(source_pack_artifact_shard_contract_error(format!(
            "job-batch prepare progress next_job_index {} exceeds scheduled_job_count {scheduled_job_count}",
            progress.next_job_index
        )));
    }
    Ok(())
}

struct SourcePackStoredJobBatchBuilder {
    limits: SourcePackJobBatchLimits,
    next_batch_index: usize,
    current_jobs: Vec<SourcePackJob>,
    current_source_bytes: usize,
    current_source_file_count: usize,
    current_source_lines: usize,
}

impl SourcePackStoredJobBatchBuilder {
    fn new(limits: SourcePackJobBatchLimits) -> Self {
        Self {
            limits: limits.normalized(),
            next_batch_index: 0,
            current_jobs: Vec::new(),
            current_source_bytes: 0,
            current_source_file_count: 0,
            current_source_lines: 0,
        }
    }

    fn should_flush_before(&self, job: &SourcePackJob) -> bool {
        !self.current_jobs.is_empty()
            && (self.current_jobs.len() >= self.limits.max_jobs_per_batch
                || self.current_source_bytes.saturating_add(job.source_bytes)
                    > self.limits.max_source_bytes_per_batch
                || self
                    .current_source_file_count
                    .saturating_add(job.source_file_count)
                    > self.limits.max_source_files_per_batch)
    }

    #[cfg(test)]
    fn push<F>(
        &mut self,
        job: SourcePackJob,
        emit: &mut F,
    ) -> Result<Option<SourcePackJobBatchDependency>, CompileError>
    where
        F: FnMut(
            Vec<SourcePackJob>,
            usize,
            usize,
            usize,
            usize,
            usize,
            bool,
        ) -> Result<SourcePackJobBatchDependency, CompileError>,
    {
        let flushed = if self.should_flush_before(&job) {
            self.flush(emit)?
        } else {
            None
        };
        self.current_source_bytes = self.current_source_bytes.saturating_add(job.source_bytes);
        self.current_source_file_count = self
            .current_source_file_count
            .saturating_add(job.source_file_count);
        self.current_source_lines = self.current_source_lines.saturating_add(job.source_lines);
        self.current_jobs.push(job);
        Ok(flushed)
    }

    #[cfg(test)]
    fn finish<F>(
        &mut self,
        emit: &mut F,
    ) -> Result<Option<SourcePackJobBatchDependency>, CompileError>
    where
        F: FnMut(
            Vec<SourcePackJob>,
            usize,
            usize,
            usize,
            usize,
            usize,
            bool,
        ) -> Result<SourcePackJobBatchDependency, CompileError>,
    {
        self.flush(emit)
    }

    fn flush<F>(
        &mut self,
        emit: &mut F,
    ) -> Result<Option<SourcePackJobBatchDependency>, CompileError>
    where
        F: FnMut(
            Vec<SourcePackJob>,
            usize,
            usize,
            usize,
            usize,
            usize,
            bool,
        ) -> Result<SourcePackJobBatchDependency, CompileError>,
    {
        if self.current_jobs.is_empty() {
            return Ok(None);
        }
        let batch_index = self.next_batch_index;
        self.next_batch_index += 1;
        let source_bytes = std::mem::take(&mut self.current_source_bytes);
        let source_file_count = std::mem::take(&mut self.current_source_file_count);
        let source_lines = std::mem::take(&mut self.current_source_lines);
        let oversized = self.current_jobs.len() > self.limits.max_jobs_per_batch
            || source_bytes > self.limits.max_source_bytes_per_batch
            || source_file_count > self.limits.max_source_files_per_batch;
        let jobs = std::mem::take(&mut self.current_jobs);
        emit(
            jobs,
            batch_index,
            batch_index,
            source_bytes,
            source_file_count,
            source_lines,
            oversized,
        )
        .map(Some)
    }
}

fn store_source_pack_stored_job_batch_page(
    store: &SourcePackFilesystemArtifactStore,
    schedule_index: &SourcePackLibraryScheduleIndex,
    batch_jobs: Vec<SourcePackJob>,
    batch_index: usize,
    wave_index: usize,
    source_bytes: usize,
    source_file_count: usize,
    source_lines: usize,
    oversized: bool,
) -> Result<SourcePackJobBatchDependency, CompileError> {
    validate_source_pack_library_schedule_index(schedule_index, schedule_index.target)?;
    if batch_jobs.is_empty() {
        return Err(source_pack_artifact_shard_contract_error(format!(
            "job-batch page {batch_index} has no jobs"
        )));
    }
    let job_indices = batch_jobs
        .iter()
        .map(|job| job.job_index)
        .collect::<Vec<_>>();
    source_pack_manifest_unique_usize_set(
        &job_indices,
        &format!("job-batch page {batch_index} jobs"),
    )?;
    for &job_index in &job_indices {
        if job_index >= schedule_index.job_count {
            return Err(source_pack_artifact_shard_contract_error(format!(
                "job-batch page {batch_index} references job {job_index} beyond scheduled job count {}",
                schedule_index.job_count
            )));
        }
        let locator = SourcePackBuildJobBatchJobLocatorPage {
            version: SOURCE_PACK_BUILD_JOB_BATCH_JOB_LOCATOR_PAGE_VERSION,
            target: schedule_index.target,
            job_index,
            batch_index,
        };
        store.store_build_job_batch_job_locator_page(&locator, schedule_index.job_count)?;
    }

    let dependency =
        source_pack_stored_job_batch_dependency(store, schedule_index, batch_index, &batch_jobs)?;
    let batch = SourcePackJobBatch {
        batch_index,
        wave_index,
        job_indices,
        source_bytes,
        source_file_count,
        source_lines,
        oversized,
    };
    let page = SourcePackBuildJobBatchPage {
        version: SOURCE_PACK_BUILD_JOB_BATCH_PAGE_VERSION,
        target: schedule_index.target,
        batch_index,
        batch,
        dependency: dependency.clone(),
    };
    store.store_build_job_batch_page(&page)?;
    Ok(dependency)
}

fn source_pack_stored_job_batch_dependency(
    store: &SourcePackFilesystemArtifactStore,
    schedule_index: &SourcePackLibraryScheduleIndex,
    batch_index: usize,
    batch_jobs: &[SourcePackJob],
) -> Result<SourcePackJobBatchDependency, CompileError> {
    let mut dependency_batch_ranges = Vec::new();
    for job in batch_jobs {
        if matches!(job.phase, SourcePackJobPhase::Link) {
            source_pack_insert_dependency_batch_range_for_jobs(
                store,
                schedule_index,
                batch_index,
                source_pack_library_schedule_index_frontend_job_count(schedule_index),
                schedule_index.link_job_index,
                &mut dependency_batch_ranges,
            )?;
            continue;
        }
        let job_page = store.load_library_schedule_job_page_for_target(
            schedule_index.target,
            job.job_index,
            schedule_index.job_count,
        )?;
        validate_source_pack_library_schedule_job_page(
            &job_page,
            schedule_index.target,
            schedule_index.job_count,
            Some(job.job_index),
        )?;
        for range in &job_page.dependency_job_ranges {
            let Some(end_job_index) = range.end_job_index() else {
                return Err(source_pack_artifact_shard_contract_error(format!(
                    "job-batch page {batch_index} dependency job range starting at {} overflows",
                    range.first_job_index
                )));
            };
            source_pack_insert_dependency_batch_range_for_jobs(
                store,
                schedule_index,
                batch_index,
                range.first_job_index,
                end_job_index,
                &mut dependency_batch_ranges,
            )?;
        }
    }
    let mut dependency = SourcePackJobBatchDependency {
        batch_index,
        dependency_batch_count: 0,
        dependency_page_count: 0,
        dependency_range_count: 0,
        dependency_range_page_count: 0,
        dependency_range_batch_count: 0,
        dependency_batch_indices: Vec::new(),
        dependency_batch_ranges,
    };
    source_pack_validate_job_batch_dependency_ranges(
        &dependency,
        &BTreeSet::new(),
        &format!("job-batch page {batch_index}"),
        batch_index,
        None,
        |message| source_pack_artifact_shard_contract_error(message),
    )?;
    let mut writer =
        SourcePackBuildJobBatchDependencyPageWriter::new(store, schedule_index.target, batch_index);
    for job in batch_jobs {
        if matches!(job.phase, SourcePackJobPhase::Link) {
            continue;
        }
        let job_page = store.load_library_schedule_job_page_for_target(
            schedule_index.target,
            job.job_index,
            schedule_index.job_count,
        )?;
        source_pack_for_each_schedule_job_explicit_dependency_index(
            store,
            schedule_index,
            &job_page,
            |dependency_job_index| {
                source_pack_write_dependency_batch_for_job(
                    store,
                    schedule_index,
                    batch_index,
                    dependency_job_index,
                    &dependency.dependency_batch_ranges,
                    &mut writer,
                )
            },
        )?;
    }
    let (dependency_batch_count, dependency_page_count) = writer.finish()?;
    dependency.dependency_batch_count = dependency_batch_count;
    dependency.dependency_page_count = dependency_page_count;
    dependency.dependency_range_count = dependency.dependency_batch_ranges.len();
    dependency.dependency_range_batch_count =
        dependency
            .dependency_batch_ranges
            .iter()
            .try_fold(0usize, |count, range| {
                count.checked_add(range.batch_count).ok_or_else(|| {
                    source_pack_artifact_shard_contract_error(format!(
                        "job-batch page {batch_index} dependency range batch count overflows"
                    ))
                })
            })?;
    source_pack_validate_job_batch_dependency_range_metadata(
        &dependency,
        &format!("job-batch page {batch_index}"),
        |message| source_pack_artifact_shard_contract_error(message),
    )?;
    Ok(dependency)
}

fn source_pack_insert_dependency_batch_range_for_jobs(
    store: &SourcePackFilesystemArtifactStore,
    schedule_index: &SourcePackLibraryScheduleIndex,
    batch_index: usize,
    first_dependency_job_index: usize,
    end_dependency_job_index: usize,
    dependency_batch_ranges: &mut Vec<SourcePackJobBatchDependencyRange>,
) -> Result<(), CompileError> {
    if first_dependency_job_index >= end_dependency_job_index {
        return Ok(());
    }
    let first_locator = store.load_build_job_batch_job_locator_page_for_target(
        schedule_index.target,
        first_dependency_job_index,
        schedule_index.job_count,
    )?;
    let last_dependency_job_index = end_dependency_job_index - 1;
    let last_locator = store.load_build_job_batch_job_locator_page_for_target(
        schedule_index.target,
        last_dependency_job_index,
        schedule_index.job_count,
    )?;
    if first_locator.batch_index > batch_index {
        return Err(source_pack_artifact_shard_contract_error(format!(
            "job-batch page {batch_index} depends on future batch {} through job {first_dependency_job_index}",
            first_locator.batch_index
        )));
    }
    if last_locator.batch_index > batch_index {
        return Err(source_pack_artifact_shard_contract_error(format!(
            "job-batch page {batch_index} depends on future batch {} through job {last_dependency_job_index}",
            last_locator.batch_index
        )));
    }
    let range_end = last_locator.batch_index.saturating_add(1).min(batch_index);
    if first_locator.batch_index >= range_end {
        return Ok(());
    }
    source_pack_push_dependency_batch_range(
        dependency_batch_ranges,
        first_locator.batch_index,
        range_end - first_locator.batch_index,
    )?;
    Ok(())
}

fn source_pack_push_dependency_batch_range(
    dependency_batch_ranges: &mut Vec<SourcePackJobBatchDependencyRange>,
    first_batch_index: usize,
    batch_count: usize,
) -> Result<(), CompileError> {
    if batch_count == 0 {
        return Ok(());
    }
    first_batch_index.checked_add(batch_count).ok_or_else(|| {
        source_pack_artifact_shard_contract_error(format!(
            "dependency batch range {first_batch_index}+{batch_count} overflows"
        ))
    })?;
    dependency_batch_ranges.push(SourcePackJobBatchDependencyRange {
        first_batch_index,
        batch_count,
    });
    dependency_batch_ranges.sort_by_key(|range| range.first_batch_index);
    let mut merged =
        Vec::<SourcePackJobBatchDependencyRange>::with_capacity(dependency_batch_ranges.len());
    for range in dependency_batch_ranges.drain(..) {
        let Some(range_end) = range.end_batch_index() else {
            return Err(source_pack_artifact_shard_contract_error(format!(
                "dependency batch range starting at {} overflows",
                range.first_batch_index
            )));
        };
        if let Some(last) = merged.last_mut() {
            let Some(last_end) = last.end_batch_index() else {
                return Err(source_pack_artifact_shard_contract_error(format!(
                    "dependency batch range starting at {} overflows",
                    last.first_batch_index
                )));
            };
            if range.first_batch_index <= last_end {
                let merged_end = last_end.max(range_end);
                last.batch_count = merged_end - last.first_batch_index;
                continue;
            }
        }
        merged.push(range);
    }
    *dependency_batch_ranges = merged;
    Ok(())
}

fn source_pack_write_dependency_batch_for_job(
    store: &SourcePackFilesystemArtifactStore,
    schedule_index: &SourcePackLibraryScheduleIndex,
    batch_index: usize,
    dependency_job_index: usize,
    dependency_batch_ranges: &[SourcePackJobBatchDependencyRange],
    writer: &mut SourcePackBuildJobBatchDependencyPageWriter<'_>,
) -> Result<(), CompileError> {
    let locator = store.load_build_job_batch_job_locator_page_for_target(
        schedule_index.target,
        dependency_job_index,
        schedule_index.job_count,
    )?;
    if locator.batch_index > batch_index {
        return Err(source_pack_artifact_shard_contract_error(format!(
            "job-batch page {batch_index} depends on future batch {} through job {dependency_job_index}",
            locator.batch_index
        )));
    }
    if locator.batch_index == batch_index
        || dependency_batch_ranges
            .iter()
            .any(|range| range.contains(locator.batch_index))
    {
        return Ok(());
    }
    writer.push(locator.batch_index)
}

#[cfg(test)]
fn store_source_pack_build_link_batch_pages_from_stored_artifact_ref_pages(
    store: &SourcePackFilesystemArtifactStore,
    target: SourcePackArtifactTarget,
    schedule_index: &SourcePackLibraryScheduleIndex,
    artifact_ref_index: &SourcePackBuildArtifactRefIndex,
    batch_limits: SourcePackJobBatchLimits,
) -> Result<SourcePackBuildLinkBatchPageIndex, CompileError> {
    validate_source_pack_library_schedule_index(schedule_index, target)?;
    validate_source_pack_build_artifact_ref_index(artifact_ref_index, target)?;
    if artifact_ref_index.artifact_count != schedule_index.job_count {
        return Err(source_pack_artifact_shard_contract_error(format!(
            "artifact-ref index has artifact_count {} but schedule has job_count {}",
            artifact_ref_index.artifact_count, schedule_index.job_count
        )));
    }
    let frontend_job_count = source_pack_library_schedule_index_frontend_job_count(schedule_index);
    if artifact_ref_index.interface_artifact_count != frontend_job_count {
        return Err(source_pack_artifact_shard_contract_error(format!(
            "artifact-ref index has {} interface artifacts but schedule has {} frontend jobs",
            artifact_ref_index.interface_artifact_count, frontend_job_count
        )));
    }
    if artifact_ref_index.object_artifact_count != schedule_index.codegen_job_count {
        return Err(source_pack_artifact_shard_contract_error(format!(
            "artifact-ref index has {} object artifacts but schedule has {} codegen jobs",
            artifact_ref_index.object_artifact_count, schedule_index.codegen_job_count
        )));
    }
    let link_interface_batch_count =
        store_source_pack_build_link_interface_batch_pages_from_stored_artifact_ref_pages(
            store,
            target,
            artifact_ref_index,
            0..frontend_job_count,
            batch_limits,
        )?;
    let link_object_batch_count =
        store_source_pack_build_link_object_batch_pages_from_stored_artifact_ref_pages(
            store,
            target,
            artifact_ref_index,
            frontend_job_count..schedule_index.link_job_index,
            batch_limits,
        )?;
    let index = SourcePackBuildLinkBatchPageIndex {
        version: SOURCE_PACK_BUILD_LINK_BATCH_PAGE_INDEX_VERSION,
        target,
        link_interface_batch_count,
        link_object_batch_count,
    };
    validate_source_pack_build_link_batch_page_index(&index, target)?;
    store.store_build_link_batch_page_index(&index)?;
    Ok(index)
}

#[derive(Clone, Debug, PartialEq, Eq, Serialize, Deserialize)]
struct SourcePackBuildLinkBatchPrepareProgress {
    version: u32,
    target: SourcePackArtifactTarget,
    batch_limits: SourcePackJobBatchLimits,
    artifact_count: usize,
    interface_artifact_count: usize,
    object_artifact_count: usize,
    next_interface_artifact_index: usize,
    next_interface_batch_index: usize,
    next_object_artifact_index: usize,
    next_object_batch_index: usize,
}

fn validate_source_pack_build_link_batch_prepare_progress(
    progress: &SourcePackBuildLinkBatchPrepareProgress,
    target: SourcePackArtifactTarget,
    artifact_ref_index: &SourcePackBuildArtifactRefIndex,
    batch_limits: SourcePackJobBatchLimits,
) -> Result<(), CompileError> {
    if progress.version != SOURCE_PACK_BUILD_LINK_BATCH_PREPARE_PROGRESS_VERSION {
        return Err(CompileError::GpuFrontend(format!(
            "unsupported source-pack link-batch prepare progress version {}; expected {}",
            progress.version, SOURCE_PACK_BUILD_LINK_BATCH_PREPARE_PROGRESS_VERSION
        )));
    }
    if progress.target != target {
        return Err(source_pack_artifact_shard_contract_error(format!(
            "link-batch prepare progress target {:?} does not match requested target {:?}",
            progress.target, target
        )));
    }
    if progress.batch_limits != batch_limits.normalized() {
        return Err(source_pack_artifact_shard_contract_error(
            "link-batch prepare progress was created with different batch limits",
        ));
    }
    if progress.artifact_count != artifact_ref_index.artifact_count
        || progress.interface_artifact_count != artifact_ref_index.interface_artifact_count
        || progress.object_artifact_count != artifact_ref_index.object_artifact_count
    {
        return Err(source_pack_artifact_shard_contract_error(
            "link-batch prepare progress artifact counts do not match artifact-ref index",
        ));
    }
    if progress.next_interface_artifact_index > artifact_ref_index.interface_artifact_count {
        return Err(source_pack_artifact_shard_contract_error(format!(
            "link-batch prepare progress next interface artifact {} exceeds count {}",
            progress.next_interface_artifact_index, artifact_ref_index.interface_artifact_count
        )));
    }
    let object_start = artifact_ref_index.interface_artifact_count;
    let object_end = object_start
        .checked_add(artifact_ref_index.object_artifact_count)
        .ok_or_else(|| {
            source_pack_artifact_shard_contract_error("object artifact range overflows")
        })?;
    if progress.next_object_artifact_index < object_start
        || progress.next_object_artifact_index > object_end
    {
        return Err(source_pack_artifact_shard_contract_error(format!(
            "link-batch prepare progress next object artifact {} is outside {}..={}",
            progress.next_object_artifact_index, object_start, object_end
        )));
    }
    Ok(())
}

fn store_source_pack_build_link_batch_pages_from_stored_artifact_ref_pages_chunk(
    store: &SourcePackFilesystemArtifactStore,
    target: SourcePackArtifactTarget,
    schedule_index: &SourcePackLibraryScheduleIndex,
    artifact_ref_index: &SourcePackBuildArtifactRefIndex,
    batch_limits: SourcePackJobBatchLimits,
    max_new_batches: usize,
) -> Result<SourcePackFilesystemLinkBatchPrepareStepResult, CompileError> {
    if max_new_batches == 0 {
        return Err(CompileError::GpuFrontend(
            "source-pack link-batch chunk max_new_batches must be greater than zero".into(),
        ));
    }
    validate_source_pack_library_schedule_index(schedule_index, target)?;
    validate_source_pack_build_artifact_ref_index(artifact_ref_index, target)?;
    if store
        .build_link_batch_index_path_for_target(target)
        .is_file()
    {
        let index = store.load_build_link_batch_page_index_for_target(target)?;
        return Ok(SourcePackFilesystemLinkBatchPrepareStepResult {
            target,
            complete: true,
            link_interface_batch_count: index.link_interface_batch_count,
            link_object_batch_count: index.link_object_batch_count,
            new_batch_count: 0,
            next_interface_artifact_index: artifact_ref_index.interface_artifact_count,
            next_object_artifact_index: artifact_ref_index
                .interface_artifact_count
                .saturating_add(artifact_ref_index.object_artifact_count),
            link_batch_index_path: Some(store.build_link_batch_index_path_for_target(target)),
        });
    }
    let frontend_job_count = source_pack_library_schedule_index_frontend_job_count(schedule_index);
    if artifact_ref_index.artifact_count != schedule_index.job_count
        || artifact_ref_index.interface_artifact_count != frontend_job_count
        || artifact_ref_index.object_artifact_count != schedule_index.codegen_job_count
    {
        return Err(source_pack_artifact_shard_contract_error(
            "artifact-ref index does not match schedule index for link-batch chunks",
        ));
    }

    let progress_path = store.build_link_batch_prepare_progress_path_for_target(target);
    let object_start = frontend_job_count;
    let object_end = schedule_index.link_job_index;
    let mut progress = if progress_path.is_file() {
        store.load_build_link_batch_prepare_progress_for_target(
            target,
            artifact_ref_index,
            batch_limits,
        )?
    } else {
        SourcePackBuildLinkBatchPrepareProgress {
            version: SOURCE_PACK_BUILD_LINK_BATCH_PREPARE_PROGRESS_VERSION,
            target,
            batch_limits: batch_limits.normalized(),
            artifact_count: artifact_ref_index.artifact_count,
            interface_artifact_count: artifact_ref_index.interface_artifact_count,
            object_artifact_count: artifact_ref_index.object_artifact_count,
            next_interface_artifact_index: 0,
            next_interface_batch_index: 0,
            next_object_artifact_index: object_start,
            next_object_batch_index: 0,
        }
    };
    validate_source_pack_build_link_batch_prepare_progress(
        &progress,
        target,
        artifact_ref_index,
        batch_limits,
    )?;

    let mut new_batch_count = 0usize;
    if progress.next_interface_artifact_index < frontend_job_count {
        let step = store_source_pack_build_link_interface_batch_pages_from_stored_artifact_ref_pages_chunk(
            store,
            target,
            artifact_ref_index,
            progress.next_interface_artifact_index,
            frontend_job_count,
            progress.next_interface_batch_index,
            batch_limits,
            max_new_batches,
        )?;
        progress.next_interface_artifact_index = step.next_artifact_index;
        progress.next_interface_batch_index = step.next_batch_index;
        new_batch_count += step.new_batch_count;
        store.store_build_link_batch_prepare_progress(&progress)?;
        if new_batch_count >= max_new_batches
            && progress.next_interface_artifact_index < frontend_job_count
        {
            return Ok(SourcePackFilesystemLinkBatchPrepareStepResult {
                target,
                complete: false,
                link_interface_batch_count: progress.next_interface_batch_index,
                link_object_batch_count: progress.next_object_batch_index,
                new_batch_count,
                next_interface_artifact_index: progress.next_interface_artifact_index,
                next_object_artifact_index: progress.next_object_artifact_index,
                link_batch_index_path: None,
            });
        }
    }

    if progress.next_object_artifact_index < object_end {
        let remaining_new_batches = max_new_batches.saturating_sub(new_batch_count);
        if remaining_new_batches == 0 {
            return Ok(SourcePackFilesystemLinkBatchPrepareStepResult {
                target,
                complete: false,
                link_interface_batch_count: progress.next_interface_batch_index,
                link_object_batch_count: progress.next_object_batch_index,
                new_batch_count,
                next_interface_artifact_index: progress.next_interface_artifact_index,
                next_object_artifact_index: progress.next_object_artifact_index,
                link_batch_index_path: None,
            });
        }
        let step =
            store_source_pack_build_link_object_batch_pages_from_stored_artifact_ref_pages_chunk(
                store,
                target,
                artifact_ref_index,
                progress.next_object_artifact_index,
                object_end,
                progress.next_object_batch_index,
                batch_limits,
                remaining_new_batches,
            )?;
        progress.next_object_artifact_index = step.next_artifact_index;
        progress.next_object_batch_index = step.next_batch_index;
        new_batch_count += step.new_batch_count;
        store.store_build_link_batch_prepare_progress(&progress)?;
        if new_batch_count >= max_new_batches && progress.next_object_artifact_index < object_end {
            return Ok(SourcePackFilesystemLinkBatchPrepareStepResult {
                target,
                complete: false,
                link_interface_batch_count: progress.next_interface_batch_index,
                link_object_batch_count: progress.next_object_batch_index,
                new_batch_count,
                next_interface_artifact_index: progress.next_interface_artifact_index,
                next_object_artifact_index: progress.next_object_artifact_index,
                link_batch_index_path: None,
            });
        }
    }

    if progress.next_interface_artifact_index != frontend_job_count
        || progress.next_object_artifact_index != object_end
    {
        return Ok(SourcePackFilesystemLinkBatchPrepareStepResult {
            target,
            complete: false,
            link_interface_batch_count: progress.next_interface_batch_index,
            link_object_batch_count: progress.next_object_batch_index,
            new_batch_count,
            next_interface_artifact_index: progress.next_interface_artifact_index,
            next_object_artifact_index: progress.next_object_artifact_index,
            link_batch_index_path: None,
        });
    }
    let index = SourcePackBuildLinkBatchPageIndex {
        version: SOURCE_PACK_BUILD_LINK_BATCH_PAGE_INDEX_VERSION,
        target,
        link_interface_batch_count: progress.next_interface_batch_index,
        link_object_batch_count: progress.next_object_batch_index,
    };
    validate_source_pack_build_link_batch_page_index(&index, target)?;
    let link_batch_index_path = store.store_build_link_batch_page_index(&index)?;
    Ok(SourcePackFilesystemLinkBatchPrepareStepResult {
        target,
        complete: true,
        link_interface_batch_count: index.link_interface_batch_count,
        link_object_batch_count: index.link_object_batch_count,
        new_batch_count,
        next_interface_artifact_index: progress.next_interface_artifact_index,
        next_object_artifact_index: progress.next_object_artifact_index,
        link_batch_index_path: Some(link_batch_index_path),
    })
}

#[cfg(test)]
fn store_source_pack_build_link_interface_batch_pages_from_stored_artifact_ref_pages(
    store: &SourcePackFilesystemArtifactStore,
    target: SourcePackArtifactTarget,
    artifact_ref_index: &SourcePackBuildArtifactRefIndex,
    artifact_indices: std::ops::Range<usize>,
    batch_limits: SourcePackJobBatchLimits,
) -> Result<usize, CompileError> {
    let limits = batch_limits.normalized();
    let max_input_artifacts_per_batch = source_pack_link_batch_input_limit(batch_limits);
    let mut batch_count = 0usize;
    let mut current_artifacts = Vec::new();
    let mut current_source_bytes = 0usize;
    let mut current_source_file_count = 0usize;
    let mut current_source_lines = 0usize;

    let flush = |batch_count: &mut usize,
                 current_artifacts: &mut Vec<usize>,
                 current_source_bytes: &mut usize,
                 current_source_file_count: &mut usize,
                 current_source_lines: &mut usize|
     -> Result<(), CompileError> {
        if current_artifacts.is_empty() {
            return Ok(());
        }
        let batch = SourcePackLinkInterfaceBatch {
            batch_index: *batch_count,
            input_interface_artifact_indices: std::mem::take(current_artifacts),
            source_bytes: std::mem::take(current_source_bytes),
            source_file_count: std::mem::take(current_source_file_count),
            source_lines: std::mem::take(current_source_lines),
        };
        let page = SourcePackBuildLinkInterfaceBatchPage {
            version: SOURCE_PACK_BUILD_LINK_INTERFACE_BATCH_PAGE_VERSION,
            target,
            batch_index: batch.batch_index,
            batch,
        };
        store.store_build_link_interface_batch_page(&page)?;
        *batch_count += 1;
        Ok(())
    };

    for artifact_index in artifact_indices {
        let page = source_pack_load_artifact_ref_page_for_index(
            store,
            target,
            artifact_ref_index,
            artifact_index,
        )?;
        if page.artifact_ref.kind != SourcePackArtifactKind::LibraryInterface {
            return Err(source_pack_artifact_shard_contract_error(format!(
                "link-interface batch input artifact {} has kind {:?}",
                page.artifact_index, page.artifact_ref.kind
            )));
        }
        let should_flush = !current_artifacts.is_empty()
            && (current_artifacts.len() >= max_input_artifacts_per_batch
                || current_source_bytes.saturating_add(page.source_bytes)
                    > limits.max_source_bytes_per_batch
                || current_source_file_count.saturating_add(page.source_file_count)
                    > limits.max_source_files_per_batch);
        if should_flush {
            flush(
                &mut batch_count,
                &mut current_artifacts,
                &mut current_source_bytes,
                &mut current_source_file_count,
                &mut current_source_lines,
            )?;
        }
        current_artifacts.push(page.artifact_index);
        current_source_bytes = current_source_bytes.saturating_add(page.source_bytes);
        current_source_file_count =
            current_source_file_count.saturating_add(page.source_file_count);
        current_source_lines = current_source_lines.saturating_add(page.source_lines);
    }
    flush(
        &mut batch_count,
        &mut current_artifacts,
        &mut current_source_bytes,
        &mut current_source_file_count,
        &mut current_source_lines,
    )?;
    Ok(batch_count)
}

