fn source_pack_filesystem_artifact_path(root: &Path, key: &str) -> Result<PathBuf, CompileError> {
    if key.is_empty() {
        return Err(CompileError::GpuFrontend(
            "source-pack artifact key cannot be empty".into(),
        ));
    }

    let mut path = root.to_path_buf();
    for component in Path::new(key).components() {
        match component {
            std::path::Component::Normal(segment) => path.push(segment),
            _ => {
                return Err(CompileError::GpuFrontend(format!(
                    "source-pack artifact key {key:?} is not relative and normal"
                )));
            }
        }
    }
    Ok(path)
}

fn read_source_pack_filesystem_artifact(
    root: &Path,
    key: &str,
    artifact_label: &str,
) -> Result<Vec<u8>, CompileError> {
    let path = source_pack_filesystem_artifact_path(root, key)?;
    fs::read(&path).map_err(|err| {
        CompileError::GpuFrontend(format!(
            "read source-pack {artifact_label} artifact {key:?} from {}: {err}",
            path.display()
        ))
    })
}

fn write_source_pack_filesystem_artifact(
    root: &Path,
    key: &str,
    artifact_label: &str,
    bytes: Vec<u8>,
) -> Result<(), CompileError> {
    let path = source_pack_filesystem_artifact_path(root, key)?;
    if let Some(parent) = path.parent() {
        fs::create_dir_all(parent).map_err(|err| {
            CompileError::GpuFrontend(format!(
                "create source-pack {artifact_label} artifact directory {}: {err}",
                parent.display()
            ))
        })?;
    }
    fs::write(&path, bytes).map_err(|err| {
        CompileError::GpuFrontend(format!(
            "write source-pack {artifact_label} artifact {key:?} to {}: {err}",
            path.display()
        ))
    })
}

fn source_pack_filesystem_artifact_path_handle(
    root: &Path,
    key: &str,
    artifact_label: &str,
) -> Result<SourcePackFilesystemArtifactPath, CompileError> {
    let path = source_pack_filesystem_artifact_path(root, key)?;
    if !path.is_file() {
        return Err(CompileError::GpuFrontend(format!(
            "source-pack {artifact_label} artifact {key:?} is missing at {}",
            path.display()
        )));
    }
    Ok(SourcePackFilesystemArtifactPath {
        key: key.to_string(),
        path,
    })
}

fn copy_source_pack_filesystem_artifact_file_atomically(
    root: &Path,
    key: &str,
    artifact_label: &str,
    artifact: SourcePackFilesystemArtifactPath,
) -> Result<(), CompileError> {
    let path = source_pack_filesystem_artifact_path(root, key)?;
    if artifact.path == path {
        if path.is_file() {
            return Ok(());
        }
        return Err(CompileError::GpuFrontend(format!(
            "source-pack {artifact_label} artifact {key:?} was returned at {} but the file is missing",
            path.display()
        )));
    }
    if !artifact.path.is_file() {
        return Err(CompileError::GpuFrontend(format!(
            "source-pack {artifact_label} artifact source {} for key {:?} is missing",
            artifact.path.display(),
            artifact.key
        )));
    }
    if let Some(parent) = path.parent() {
        fs::create_dir_all(parent).map_err(|err| {
            CompileError::GpuFrontend(format!(
                "create source-pack {artifact_label} artifact directory {}: {err}",
                parent.display()
            ))
        })?;
    }
    let file_name = path.file_name().ok_or_else(|| {
        CompileError::GpuFrontend(format!(
            "source-pack {artifact_label} artifact path {} has no file name",
            path.display()
        ))
    })?;
    let mut tmp_file_name = file_name.to_os_string();
    tmp_file_name.push(format!(
        ".tmp-{}-{}",
        std::process::id(),
        source_pack_build_now_unix_nanos()?
    ));
    let tmp_path = path.with_file_name(tmp_file_name);
    fs::copy(&artifact.path, &tmp_path).map_err(|err| {
        CompileError::GpuFrontend(format!(
            "copy source-pack {artifact_label} artifact {:?} from {} to temporary {}: {err}",
            artifact.key,
            artifact.path.display(),
            tmp_path.display()
        ))
    })?;
    fs::rename(&tmp_path, &path).map_err(|err| {
        let _ = fs::remove_file(&tmp_path);
        CompileError::GpuFrontend(format!(
            "replace source-pack {artifact_label} artifact {key:?} at {} with temporary {}: {err}",
            path.display(),
            tmp_path.display()
        ))
    })
}

fn remove_source_pack_filesystem_artifact(
    root: &Path,
    key: &str,
    artifact_label: &str,
) -> Result<(), CompileError> {
    let path = source_pack_filesystem_artifact_path(root, key)?;
    match fs::remove_file(&path) {
        Ok(()) => Ok(()),
        Err(err) if err.kind() == std::io::ErrorKind::NotFound => Ok(()),
        Err(err) => Err(CompileError::GpuFrontend(format!(
            "release source-pack {artifact_label} artifact {key:?} at {}: {err}",
            path.display()
        ))),
    }
}

fn execute_source_pack_build<E>(
    source_pack: &ExplicitSourcePack,
    build_plan: &SourcePackBuildPlan,
    batch_limits: SourcePackJobBatchLimits,
    executor: &mut E,
) -> Result<
    SourcePackBuildExecutionResult<E::LibraryInterface, E::CodegenObject, E::LinkedOutput>,
    CompileError,
>
where
    E: SourcePackBuildExecutor,
{
    let mut library_interfaces = Vec::new();
    let mut codegen_objects = Vec::new();
    let mut interface_by_job = vec![None; build_plan.schedule.jobs.len()];
    let mut object_by_job = vec![None; build_plan.schedule.jobs.len()];
    let mut linked_output = None;

    build_plan.schedule.try_for_each_execution_batch(
        batch_limits,
        source_pack_schedule_error,
        |batch| {
            for &job_index in &batch.job_indices {
                let job = source_pack_schedule_job(&build_plan.schedule, job_index)?;
                match job.phase {
                    SourcePackJobPhase::LibraryFrontend => {
                        let dependency_interfaces = collect_interface_refs(
                            &library_interfaces,
                            &interface_by_job,
                            &build_plan.schedule,
                            job,
                        )?;
                        let interface = executor.build_library_interface(
                            job,
                            source_pack.source_slice_for_job(job),
                            &dependency_interfaces,
                        )?;
                        interface_by_job[job.job_index] = Some(library_interfaces.len());
                        library_interfaces.push(interface);
                    }
                    SourcePackJobPhase::Codegen => {
                        let library_job_index = job.library_job_index.ok_or_else(|| {
                            CompileError::GpuFrontend(format!(
                                "source-pack codegen job {} has no owning library job",
                                job.job_index
                            ))
                        })?;
                        let library_interface_index = interface_by_job
                        .get(library_job_index)
                        .and_then(|index| *index)
                        .ok_or_else(|| {
                            CompileError::GpuFrontend(format!(
                                "source-pack codegen job {} missing library interface from job {}",
                                job.job_index, library_job_index
                            ))
                        })?;
                        let library_interface = &library_interfaces[library_interface_index];
                        let dependency_interfaces = collect_interface_refs_excluding(
                            &library_interfaces,
                            &interface_by_job,
                            &build_plan.schedule,
                            job,
                            Some(library_job_index),
                        )?;
                        let object = executor.build_codegen_object(
                            job,
                            source_pack.source_slice_for_job(job),
                            library_interface,
                            &dependency_interfaces,
                        )?;
                        object_by_job[job.job_index] = Some(codegen_objects.len());
                        codegen_objects.push(object);
                    }
                    SourcePackJobPhase::Link => {
                        let interface_refs = collect_link_interface_refs(
                            &library_interfaces,
                            &interface_by_job,
                            build_plan,
                        )?;
                        let object_refs =
                            collect_link_object_refs(&codegen_objects, &object_by_job, build_plan)?;
                        linked_output = Some(executor.link_codegen_objects(
                            job,
                            &interface_refs,
                            &object_refs,
                        )?);
                    }
                }
            }
            Ok(())
        },
    )?;

    let linked_output = linked_output.ok_or_else(|| {
        CompileError::GpuFrontend("source-pack build plan did not execute a link job".into())
    })?;

    Ok(SourcePackBuildExecutionResult {
        library_interfaces,
        codegen_objects,
        linked_output,
    })
}

