fn release_link_input_handles<E>(
    build_plan: &SourcePackBuildPlan,
    library_interfaces: &mut [Option<E::LibraryInterfaceHandle>],
    codegen_objects: &mut [Option<E::CodegenObjectHandle>],
    executor: &mut E,
) -> Result<(), CompileError>
where
    E: SourcePackPathHandleBuildExecutor,
{
    let mut released_interfaces = BTreeSet::new();
    build_plan
        .link
        .try_for_each_input_interface_artifact_index(|artifact_index| {
            if !released_interfaces.insert(artifact_index) {
                return Ok(());
            }
            let Some(artifact) = build_plan.artifacts.get(artifact_index) else {
                return Ok(());
            };
            if artifact.kind != SourcePackArtifactKind::LibraryInterface {
                return Ok(());
            }
            if let Some(handle) = library_interfaces
                .get_mut(artifact.producing_job_index)
                .and_then(Option::take)
            {
                executor.release_library_interface(handle)?;
            }
            Ok::<(), CompileError>(())
        })?;

    let mut released_objects = BTreeSet::new();
    build_plan
        .link
        .try_for_each_input_object_artifact_index(|artifact_index| {
            if !released_objects.insert(artifact_index) {
                return Ok(());
            }
            let Some(artifact) = build_plan.artifacts.get(artifact_index) else {
                return Ok(());
            };
            if artifact.kind != SourcePackArtifactKind::CodegenObject {
                return Ok(());
            }
            if let Some(handle) = codegen_objects
                .get_mut(artifact.producing_job_index)
                .and_then(Option::take)
            {
                executor.release_codegen_object(handle)?;
            }
            Ok::<(), CompileError>(())
        })?;

    Ok(())
}

fn release_codegen_object_handles_for_link_batch<E>(
    build_plan: &SourcePackBuildPlan,
    batch: &SourcePackLinkObjectBatch,
    codegen_objects: &mut [Option<E::CodegenObjectHandle>],
    executor: &mut E,
) -> Result<(), CompileError>
where
    E: SourcePackPathHandleBatchedLinkBuildExecutor,
{
    for &artifact_index in &batch.input_object_artifact_indices {
        let Some(artifact) = build_plan.artifacts.get(artifact_index) else {
            continue;
        };
        if artifact.kind != SourcePackArtifactKind::CodegenObject {
            continue;
        }
        if let Some(handle) = codegen_objects
            .get_mut(artifact.producing_job_index)
            .and_then(Option::take)
        {
            executor.release_codegen_object(handle)?;
        }
    }
    Ok(())
}

fn release_library_interface_handles_for_link_batch<E>(
    build_plan: &SourcePackBuildPlan,
    batch: &SourcePackLinkInterfaceBatch,
    library_interfaces: &mut [Option<E::LibraryInterfaceHandle>],
    executor: &mut E,
) -> Result<(), CompileError>
where
    E: SourcePackPathHandleBatchedLinkBuildExecutor,
{
    for &artifact_index in &batch.input_interface_artifact_indices {
        let Some(artifact) = build_plan.artifacts.get(artifact_index) else {
            continue;
        };
        if artifact.kind != SourcePackArtifactKind::LibraryInterface {
            continue;
        }
        if let Some(handle) = library_interfaces
            .get_mut(artifact.producing_job_index)
            .and_then(Option::take)
        {
            executor.release_library_interface(handle)?;
        }
    }
    Ok(())
}

fn collect_interface_refs<'a, T>(
    library_interfaces: &'a [T],
    interface_by_job: &[Option<usize>],
    schedule: &SourcePackJobSchedule,
    job: &SourcePackJob,
) -> Result<Vec<&'a T>, CompileError> {
    collect_interface_refs_excluding(library_interfaces, interface_by_job, schedule, job, None)
}

fn collect_interface_refs_excluding<'a, T>(
    library_interfaces: &'a [T],
    interface_by_job: &[Option<usize>],
    schedule: &SourcePackJobSchedule,
    job: &SourcePackJob,
    excluded_job_index: Option<usize>,
) -> Result<Vec<&'a T>, CompileError> {
    let mut refs = Vec::new();
    for_each_interface_dependency_job_index(
        schedule,
        job,
        excluded_job_index,
        |dependency_job_index| {
            let interface_index = interface_by_job
                .get(dependency_job_index)
                .and_then(|index| *index)
                .ok_or_else(|| {
                    CompileError::GpuFrontend(format!(
                        "source-pack job {} missing interface dependency from job {}",
                        job.job_index, dependency_job_index
                    ))
                })?;
            refs.push(&library_interfaces[interface_index]);
            Ok(())
        },
    )?;
    Ok(refs)
}

fn for_each_interface_dependency_job_index<F>(
    schedule: &SourcePackJobSchedule,
    job: &SourcePackJob,
    excluded_job_index: Option<usize>,
    mut visit: F,
) -> Result<(), CompileError>
where
    F: FnMut(usize) -> Result<(), CompileError>,
{
    let mut seen = BTreeSet::new();
    for &dependency_job_index in &job.dependency_job_indices {
        if Some(dependency_job_index) != excluded_job_index && seen.insert(dependency_job_index) {
            visit(dependency_job_index)?;
        }
    }
    for dependency_range in schedule.dependency_job_ranges_for_job(job) {
        let Some(dependency_job_indices) = dependency_range.iter() else {
            return Err(CompileError::GpuFrontend(format!(
                "source-pack job {} interface dependency range starting at {} overflows",
                job.job_index, dependency_range.first_job_index
            )));
        };
        for dependency_job_index in dependency_job_indices {
            if Some(dependency_job_index) != excluded_job_index && seen.insert(dependency_job_index)
            {
                visit(dependency_job_index)?;
            }
        }
    }
    Ok(())
}

fn collect_link_interface_refs<'a, T>(
    library_interfaces: &'a [T],
    interface_by_job: &[Option<usize>],
    build_plan: &SourcePackBuildPlan,
) -> Result<Vec<&'a T>, CompileError> {
    let mut refs = Vec::new();
    build_plan
        .link
        .try_for_each_input_interface_artifact_index(|artifact_index| {
            let artifact = build_plan.artifacts.get(artifact_index).ok_or_else(|| {
                CompileError::GpuFrontend(format!(
                    "source-pack link references missing interface artifact {artifact_index}"
                ))
            })?;
            let interface_index = interface_by_job
                .get(artifact.producing_job_index)
                .and_then(|index| *index)
                .ok_or_else(|| {
                    CompileError::GpuFrontend(format!(
                        "source-pack link missing interface from job {}",
                        artifact.producing_job_index
                    ))
                })?;
            refs.push(&library_interfaces[interface_index]);
            Ok(())
        })?;
    Ok(refs)
}

fn collect_link_object_refs<'a, T>(
    codegen_objects: &'a [T],
    object_by_job: &[Option<usize>],
    build_plan: &SourcePackBuildPlan,
) -> Result<Vec<&'a T>, CompileError> {
    let mut refs = Vec::new();
    build_plan
        .link
        .try_for_each_input_object_artifact_index(|artifact_index| {
            let artifact = build_plan.artifacts.get(artifact_index).ok_or_else(|| {
                CompileError::GpuFrontend(format!(
                    "source-pack link references missing object artifact {artifact_index}"
                ))
            })?;
            let object_index = object_by_job
                .get(artifact.producing_job_index)
                .and_then(|index| *index)
                .ok_or_else(|| {
                    CompileError::GpuFrontend(format!(
                        "source-pack link missing object from job {}",
                        artifact.producing_job_index
                    ))
                })?;
            refs.push(&codegen_objects[object_index]);
            Ok(())
        })?;
    Ok(refs)
}

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
pub struct GpuCompilerBackends {
    pub wasm: bool,
    pub x86: bool,
}

impl GpuCompilerBackends {
    pub const fn all() -> Self {
        Self {
            wasm: true,
            x86: true,
        }
    }

    pub const fn frontend_only() -> Self {
        Self {
            wasm: false,
            x86: false,
        }
    }

    pub const fn wasm_only() -> Self {
        Self {
            wasm: true,
            x86: false,
        }
    }

    pub const fn x86_only() -> Self {
        Self {
            wasm: false,
            x86: true,
        }
    }
}

pub struct GpuCompiler<'gpu> {
    gpu: &'gpu GpuDevice,
    lexer: GpuLexer,
    parser: GpuParser,
    parse_tables: PrecomputedParseTables,
    type_checker: gpu_type_checker::GpuTypeChecker,
    resident_pipeline_lock: Mutex<()>,
    wasm_generator: Result<Box<wasm::GpuWasmCodeGenerator>, String>,
    x86_generator: Result<Box<x86::GpuX86CodeGenerator>, String>,
}

pub struct GpuSourcePackArtifactExecutor<'compiler, 'gpu> {
    compiler: &'compiler GpuCompiler<'gpu>,
    artifact_root: PathBuf,
    target: SourcePackArtifactTarget,
}

#[derive(Clone, Debug)]
pub struct GpuSourcePackLibraryInterfaceBuildHandle {
    job: SourcePackJob,
    source_files: Vec<ExplicitSourcePathFile>,
    dependency_interfaces: GpuSourcePackDependencyInterfaceSummary,
}

#[derive(Clone, Debug)]
pub struct GpuSourcePackCodegenObjectBuildHandle {
    job: SourcePackJob,
    source_files: Vec<ExplicitSourcePathFile>,
    library_interface_artifact: SourcePackFilesystemArtifactPath,
    dependency_interfaces: GpuSourcePackDependencyInterfaceSummary,
}

#[derive(Clone, Debug, Default)]
pub struct GpuSourcePackLinkHandle {
    interface_count: usize,
    object_count: usize,
    partial_link_count: usize,
}

impl<'compiler, 'gpu> GpuSourcePackArtifactExecutor<'compiler, 'gpu> {
    pub fn new(
        compiler: &'compiler GpuCompiler<'gpu>,
        artifact_root: impl Into<PathBuf>,
        target: SourcePackArtifactTarget,
    ) -> Self {
        Self {
            compiler,
            artifact_root: artifact_root.into(),
            target,
        }
    }

    pub fn compiler(&self) -> &'compiler GpuCompiler<'gpu> {
        self.compiler
    }

    pub fn artifact_root(&self) -> &Path {
        &self.artifact_root
    }

    pub fn target(&self) -> SourcePackArtifactTarget {
        self.target
    }

    async fn finish_library_interface_artifact(
        &self,
        handle: GpuSourcePackLibraryInterfaceBuildHandle,
    ) -> Result<SourcePackFilesystemArtifactPath, CompileError> {
        self.validate_job_source_file_records(
            "library-interface",
            &handle.job,
            &handle.source_files,
        )?;
        let sources = read_explicit_source_path_files(
            "GPU source-pack library-interface job",
            &handle.source_files,
        )?;
        self.compiler.type_check_source_pack(&sources).await?;
        let descriptor = GpuSourcePackArtifactDescriptor::library_interface_for_job(
            self.target,
            &handle.job,
            handle.dependency_interfaces,
        );
        self.write_descriptor_artifact(
            GpuSourcePackArtifactStage::LibraryInterface,
            &handle.job,
            &descriptor,
        )
    }

    fn finish_codegen_object_artifact(
        &self,
        handle: GpuSourcePackCodegenObjectBuildHandle,
    ) -> Result<SourcePackFilesystemArtifactPath, CompileError> {
        self.validate_job_source_file_records("codegen", &handle.job, &handle.source_files)?;
        if !handle.library_interface_artifact.path.is_file() {
            return Err(CompileError::GpuCodegen(format!(
                "GPU source-pack codegen descriptor job {} missing owning interface artifact {}",
                handle.job.job_index,
                handle.library_interface_artifact.path.display()
            )));
        }
        let descriptor = GpuSourcePackArtifactDescriptor::codegen_object_contract_for_job(
            self.target,
            &handle.job,
            handle.dependency_interfaces,
        );
        self.write_descriptor_artifact(
            GpuSourcePackArtifactStage::CodegenObject,
            &handle.job,
            &descriptor,
        )
    }

    fn finish_linked_output_artifact(
        &self,
        job: &SourcePackJob,
        link_handle: GpuSourcePackLinkHandle,
    ) -> Result<SourcePackFilesystemArtifactPath, CompileError> {
        let descriptor = GpuSourcePackArtifactDescriptor::linked_output_contract_for_job(
            self.target,
            job,
            link_handle.interface_count,
            link_handle.object_count,
        );
        self.write_descriptor_artifact(GpuSourcePackArtifactStage::LinkedOutput, job, &descriptor)
    }

    fn finish_hierarchical_partial_link_artifact(
        &self,
        page: &SourcePackHierarchicalLinkExecutionPage,
        link_handle: GpuSourcePackLinkHandle,
    ) -> Result<SourcePackFilesystemArtifactPath, CompileError> {
        let descriptor = GpuSourcePackArtifactDescriptor::partial_link_contract_for_page(
            page,
            link_handle.interface_count,
            link_handle.object_count,
            link_handle.partial_link_count,
        );
        self.write_descriptor_artifact_for_suffix(
            GpuSourcePackArtifactStage::PartialLink,
            format!("group-{}", page.group_index),
            &descriptor,
        )
    }

    fn finish_hierarchical_linked_output_artifact(
        &self,
        page: &SourcePackHierarchicalLinkExecutionPage,
        link_handle: GpuSourcePackLinkHandle,
    ) -> Result<SourcePackFilesystemArtifactPath, CompileError> {
        let descriptor =
            GpuSourcePackArtifactDescriptor::hierarchical_linked_output_contract_for_page(
                page,
                link_handle.interface_count,
                link_handle.object_count,
                link_handle.partial_link_count,
            );
        self.write_descriptor_artifact_for_suffix(
            GpuSourcePackArtifactStage::LinkedOutput,
            format!("group-{}", page.group_index),
            &descriptor,
        )
    }

    fn write_descriptor_artifact(
        &self,
        stage: GpuSourcePackArtifactStage,
        job: &SourcePackJob,
        descriptor: &GpuSourcePackArtifactDescriptor,
    ) -> Result<SourcePackFilesystemArtifactPath, CompileError> {
        self.write_descriptor_artifact_for_suffix(
            stage,
            format!("job-{}", job.job_index),
            descriptor,
        )
    }

    fn write_descriptor_artifact_for_suffix(
        &self,
        stage: GpuSourcePackArtifactStage,
        key_suffix: impl AsRef<str>,
        descriptor: &GpuSourcePackArtifactDescriptor,
    ) -> Result<SourcePackFilesystemArtifactPath, CompileError> {
        let key = gpu_source_pack_descriptor_artifact_key(self.target, stage, key_suffix.as_ref());
        let path = source_pack_filesystem_artifact_path(&self.artifact_root, &key)?;
        if let Some(parent) = path.parent() {
            fs::create_dir_all(parent).map_err(|err| {
                CompileError::GpuFrontend(format!(
                    "create GPU source-pack descriptor artifact directory {}: {err}",
                    parent.display()
                ))
            })?;
        }
        let bytes = serde_json::to_vec_pretty(descriptor).map_err(|err| {
            CompileError::GpuFrontend(format!(
                "serialize GPU source-pack {:?} descriptor for {}: {err}",
                stage,
                key_suffix.as_ref()
            ))
        })?;
        write_source_pack_filesystem_file_atomically(
            &path,
            &bytes,
            "GPU source-pack descriptor artifact",
        )?;
        Ok(SourcePackFilesystemArtifactPath { key, path })
    }

    fn validate_job_source_file_records(
        &self,
        stage: &str,
        job: &SourcePackJob,
        source_files: &[ExplicitSourcePathFile],
    ) -> Result<(), CompileError> {
        let expected_phase = match stage {
            "library-interface" => Some(SourcePackJobPhase::LibraryFrontend),
            "codegen" => Some(SourcePackJobPhase::Codegen),
            _ => None,
        };
        if let Some(expected_phase) = expected_phase {
            if job.phase != expected_phase {
                return Err(CompileError::GpuCodegen(format!(
                    "GPU source-pack {stage} descriptor job {} has phase {:?} but expected {:?}",
                    job.job_index, job.phase, expected_phase
                )));
            }
        }
        let source_end = job
            .first_source_index
            .checked_add(job.source_file_count)
            .ok_or_else(|| {
                CompileError::GpuCodegen(format!(
                    "GPU source-pack {stage} descriptor job {} source range {}+{} overflows",
                    job.job_index, job.first_source_index, job.source_file_count
                ))
            })?;
        if source_files.len() != job.source_file_count {
            return Err(CompileError::GpuCodegen(format!(
                "GPU source-pack {stage} descriptor job {} received {} source-file records but expected {}",
                job.job_index,
                source_files.len(),
                job.source_file_count
            )));
        }
        let mut source_bytes = 0usize;
        let mut source_lines = 0usize;
        for (offset, file) in source_files.iter().enumerate() {
            if file.library_id != job.library_id {
                let source_index = job.first_source_index.saturating_add(offset);
                return Err(CompileError::GpuCodegen(format!(
                    "GPU source-pack {stage} descriptor job {} source file {} belongs to library {} but expected {}",
                    job.job_index, source_index, file.library_id, job.library_id
                )));
            }
            source_bytes = source_bytes.checked_add(file.byte_len).ok_or_else(|| {
                CompileError::GpuCodegen(format!(
                    "GPU source-pack {stage} descriptor job {} source byte count overflows before source {}",
                    job.job_index,
                    job.first_source_index.saturating_add(offset)
                ))
            })?;
            source_lines = source_lines
                .checked_add(file.line_count.unwrap_or(0))
                .ok_or_else(|| {
                    CompileError::GpuCodegen(format!(
                        "GPU source-pack {stage} descriptor job {} source line count overflows before source {}",
                        job.job_index,
                        job.first_source_index.saturating_add(offset)
                    ))
                })?;
        }
        if source_bytes != job.source_bytes {
            return Err(CompileError::GpuCodegen(format!(
                "GPU source-pack {stage} descriptor job {} source range {}..{} has {} bytes but job record declares {}",
                job.job_index, job.first_source_index, source_end, source_bytes, job.source_bytes
            )));
        }
        if source_lines != job.source_lines {
            return Err(CompileError::GpuCodegen(format!(
                "GPU source-pack {stage} descriptor job {} source range {}..{} has {} lines but job record declares {}",
                job.job_index, job.first_source_index, source_end, source_lines, job.source_lines
            )));
        }
        Ok(())
    }

    fn validate_existing_path_artifact_batch(
        &self,
        stage: &str,
        owner_index: usize,
        artifacts: &[SourcePackFilesystemArtifactPath],
    ) -> Result<(), CompileError> {
        for artifact in artifacts {
            if !artifact.path.is_file() {
                return Err(CompileError::GpuCodegen(format!(
                    "GPU source-pack {stage} {} missing dependency artifact {} at {}",
                    owner_index,
                    artifact.key,
                    artifact.path.display()
                )));
            }
        }
        Ok(())
    }
}

fn gpu_source_pack_descriptor_artifact_key(
    target: SourcePackArtifactTarget,
    stage: GpuSourcePackArtifactStage,
    key_suffix: &str,
) -> String {
    let target = target.key_prefix().unwrap_or("generic");
    let stage = match stage {
        GpuSourcePackArtifactStage::LibraryInterface => "library-interface",
        GpuSourcePackArtifactStage::CodegenObject => "codegen-object",
        GpuSourcePackArtifactStage::PartialLink => "partial-link",
        GpuSourcePackArtifactStage::LinkedOutput => "linked-output",
    };
    format!("gpu-source-pack/{target}/{stage}/{key_suffix}.json")
}

impl<'compiler, 'gpu> SourcePackPathAsyncPagedArtifactBuildExecutor
    for GpuSourcePackArtifactExecutor<'compiler, 'gpu>
{
    type LibraryInterfaceArtifact = SourcePackFilesystemArtifactPath;
    type CodegenObjectArtifact = SourcePackFilesystemArtifactPath;
    type LinkHandle = GpuSourcePackLinkHandle;
    type LinkedOutputArtifact = SourcePackFilesystemArtifactPath;
    type LibraryInterfaceBuildHandle = GpuSourcePackLibraryInterfaceBuildHandle;
    type CodegenObjectBuildHandle = GpuSourcePackCodegenObjectBuildHandle;

    fn begin_library_interface<'a>(
        &'a mut self,
        job: &'a SourcePackJob,
        source_files: &'a [ExplicitSourcePathFile],
    ) -> SourcePackBoxFuture<'a, Self::LibraryInterfaceBuildHandle> {
        Box::pin(async move {
            Ok(GpuSourcePackLibraryInterfaceBuildHandle {
                job: job.clone(),
                source_files: source_files.to_vec(),
                dependency_interfaces: GpuSourcePackDependencyInterfaceSummary::default(),
            })
        })
    }

    fn add_library_interface_dependency_batch<'a>(
        &'a mut self,
        job: &'a SourcePackJob,
        handle: &'a mut Self::LibraryInterfaceBuildHandle,
        dependency_interfaces: &'a [Self::LibraryInterfaceArtifact],
    ) -> SourcePackBoxFuture<'a, ()> {
        Box::pin(async move {
            self.validate_existing_path_artifact_batch(
                "library-interface dependency batch",
                job.job_index,
                dependency_interfaces,
            )?;
            handle
                .dependency_interfaces
                .add_batch(dependency_interfaces.len());
            Ok(())
        })
    }

    fn finish_library_interface<'a>(
        &'a mut self,
        _job: &'a SourcePackJob,
        handle: Self::LibraryInterfaceBuildHandle,
    ) -> SourcePackBoxFuture<'a, Self::LibraryInterfaceArtifact> {
        Box::pin(async move { self.finish_library_interface_artifact(handle).await })
    }

    fn begin_codegen_object<'a>(
        &'a mut self,
        job: &'a SourcePackJob,
        source_files: &'a [ExplicitSourcePathFile],
        library_interface: &'a Self::LibraryInterfaceArtifact,
    ) -> SourcePackBoxFuture<'a, Self::CodegenObjectBuildHandle> {
        Box::pin(async move {
            Ok(GpuSourcePackCodegenObjectBuildHandle {
                job: job.clone(),
                source_files: source_files.to_vec(),
                library_interface_artifact: library_interface.clone(),
                dependency_interfaces: GpuSourcePackDependencyInterfaceSummary::default(),
            })
        })
    }

    fn add_codegen_object_dependency_batch<'a>(
        &'a mut self,
        job: &'a SourcePackJob,
        handle: &'a mut Self::CodegenObjectBuildHandle,
        dependency_interfaces: &'a [Self::LibraryInterfaceArtifact],
    ) -> SourcePackBoxFuture<'a, ()> {
        Box::pin(async move {
            self.validate_existing_path_artifact_batch(
                "codegen dependency batch",
                job.job_index,
                dependency_interfaces,
            )?;
            handle
                .dependency_interfaces
                .add_batch(dependency_interfaces.len());
            Ok(())
        })
    }

    fn finish_codegen_object<'a>(
        &'a mut self,
        _job: &'a SourcePackJob,
        handle: Self::CodegenObjectBuildHandle,
    ) -> SourcePackBoxFuture<'a, Self::CodegenObjectArtifact> {
        Box::pin(async move { self.finish_codegen_object_artifact(handle) })
    }

    fn begin_link_codegen_objects<'a>(
        &'a mut self,
        _job: &'a SourcePackJob,
    ) -> SourcePackBoxFuture<'a, Self::LinkHandle> {
        Box::pin(async move { Ok(GpuSourcePackLinkHandle::default()) })
    }

    fn link_library_interface_batch<'a>(
        &'a mut self,
        job: &'a SourcePackJob,
        link_handle: &'a mut Self::LinkHandle,
        _batch: &'a SourcePackLinkInterfaceBatch,
        library_interfaces: &'a [Self::LibraryInterfaceArtifact],
    ) -> SourcePackBoxFuture<'a, ()> {
        Box::pin(async move {
            self.validate_existing_path_artifact_batch(
                "link interface batch",
                job.job_index,
                library_interfaces,
            )?;
            link_handle.interface_count = link_handle
                .interface_count
                .saturating_add(library_interfaces.len());
            Ok(())
        })
    }

    fn link_codegen_object_batch<'a>(
        &'a mut self,
        job: &'a SourcePackJob,
        link_handle: &'a mut Self::LinkHandle,
        _batch: &'a SourcePackLinkObjectBatch,
        codegen_objects: &'a [Self::CodegenObjectArtifact],
    ) -> SourcePackBoxFuture<'a, ()> {
        Box::pin(async move {
            self.validate_existing_path_artifact_batch(
                "link object batch",
                job.job_index,
                codegen_objects,
            )?;
            link_handle.object_count = link_handle
                .object_count
                .saturating_add(codegen_objects.len());
            Ok(())
        })
    }

    fn finish_link_codegen_objects<'a>(
        &'a mut self,
        job: &'a SourcePackJob,
        link_handle: Self::LinkHandle,
    ) -> SourcePackBoxFuture<'a, Self::LinkedOutputArtifact> {
        Box::pin(async move { self.finish_linked_output_artifact(job, link_handle) })
    }
}

impl<'compiler, 'gpu> SourcePackPathAsyncHierarchicalLinkExecutor
    for GpuSourcePackArtifactExecutor<'compiler, 'gpu>
{
    type PartialLinkArtifact = SourcePackFilesystemArtifactPath;

    fn begin_hierarchical_link_group<'a>(
        &'a mut self,
        _page: &'a SourcePackHierarchicalLinkExecutionPage,
    ) -> SourcePackBoxFuture<'a, Self::LinkHandle> {
        Box::pin(async move { Ok(GpuSourcePackLinkHandle::default()) })
    }

    fn link_hierarchical_library_interfaces<'a>(
        &'a mut self,
        page: &'a SourcePackHierarchicalLinkExecutionPage,
        link_handle: &'a mut Self::LinkHandle,
        library_interfaces: &'a [Self::LibraryInterfaceArtifact],
    ) -> SourcePackBoxFuture<'a, ()> {
        Box::pin(async move {
            self.validate_existing_path_artifact_batch(
                "hierarchical link interface batch",
                page.group_index,
                library_interfaces,
            )?;
            link_handle.interface_count = link_handle
                .interface_count
                .saturating_add(library_interfaces.len());
            Ok(())
        })
    }

    fn link_hierarchical_codegen_objects<'a>(
        &'a mut self,
        page: &'a SourcePackHierarchicalLinkExecutionPage,
        link_handle: &'a mut Self::LinkHandle,
        codegen_objects: &'a [Self::CodegenObjectArtifact],
    ) -> SourcePackBoxFuture<'a, ()> {
        Box::pin(async move {
            self.validate_existing_path_artifact_batch(
                "hierarchical link object batch",
                page.group_index,
                codegen_objects,
            )?;
            link_handle.object_count = link_handle
                .object_count
                .saturating_add(codegen_objects.len());
            Ok(())
        })
    }

    fn link_hierarchical_partial_links<'a>(
        &'a mut self,
        page: &'a SourcePackHierarchicalLinkExecutionPage,
        link_handle: &'a mut Self::LinkHandle,
        partial_links: &'a [Self::PartialLinkArtifact],
    ) -> SourcePackBoxFuture<'a, ()> {
        Box::pin(async move {
            self.validate_existing_path_artifact_batch(
                "hierarchical partial-link batch",
                page.group_index,
                partial_links,
            )?;
            link_handle.partial_link_count = link_handle
                .partial_link_count
                .saturating_add(partial_links.len());
            Ok(())
        })
    }

    fn finish_hierarchical_partial_link_group<'a>(
        &'a mut self,
        page: &'a SourcePackHierarchicalLinkExecutionPage,
        link_handle: Self::LinkHandle,
    ) -> SourcePackBoxFuture<'a, Self::PartialLinkArtifact> {
        Box::pin(async move { self.finish_hierarchical_partial_link_artifact(page, link_handle) })
    }

    fn finish_hierarchical_link_output<'a>(
        &'a mut self,
        page: &'a SourcePackHierarchicalLinkExecutionPage,
        link_handle: Self::LinkHandle,
    ) -> SourcePackBoxFuture<'a, Self::LinkedOutputArtifact> {
        Box::pin(async move { self.finish_hierarchical_linked_output_artifact(page, link_handle) })
    }
}

